const questionsFr: Question[] = [
  // Gamme mineure
  { q:"Pourquoi la gamme mineure naturelle pose-t-elle un problème harmonique ?", opts:["Elle a trop de notes","Son triton ne pousse pas vers la tonique","Elle n'a pas de VIIe degré","Elle contient trop d'altérations"], a:1, fb:"En mineur naturel, le triton se trouve entre le IIe et le VIe degré — il ne résout pas vers le Ier et IIIe degrés comme en majeur. Pas de sensible fonctionnelle." },
  { q:"Comment la gamme mineure harmonique résout-elle ce problème ?", opts:["En supprimant le triton","En élevant le VIIe degré d'un demi-ton","En abaissant le IVe degré","En ajoutant une 8e note"], a:1, fb:"Élever le VIIe degré crée une sensible forte (B naturel au lieu de Bb en C mineur) et rétablit un triton fonctionnel entre le IVe et VIIe degrés — comme en majeur." },
  { q:"Qu'est-ce que la gamme mineure harmonique apporte que la naturelle n'a pas ?", opts:["Une octave supplémentaire","Une sensible et un triton fonctionnel","Trois nouvelles notes","Un accord de dominante mineur"], a:1, fb:"La mineure harmonique recrée la sensible (VII → I, demi-ton ascendant) et le triton fonctionnel (IV + VII). Sans ça, l'accord de dominante serait mineur (Gm au lieu de G7)." },
  { q:"En C mineur harmonique, quel accord forme la dominante ?", opts:["Gm","G","G7","Dm"], a:2, fb:"Avec le VIIe degré élevé (B naturel), l'accord construit sur Sol est G–B–D–F = G7. La septième mineure (F) est issue de la gamme, le B naturel vient de la mineure harmonique." },
  { q:"Sur quels degrés utilise-t-on la mineure naturelle plutôt que l'harmonique ?", opts:["IVe et Ve","Ier et IIIe","IIe et VIIe","Ve et VIe"], a:1, fb:"Les Ier (tonique) et IIIe (relatif majeur) degrés utilisent la mineure naturelle pour rester stables. La mineure harmonique sur ces degrés créerait des intervalles trop instables (7e majeure, 5te augmentée)." },
  { q:"En C mineur, quelle est la différence entre Gm (naturel) et G7 (harmonique) ?", opts:["La fondamentale","La tierce","La septième et la tierce — B♭ vs B naturel","La quinte"], a:2, fb:"En mineure naturelle : G–Bb–D = Gm. En mineure harmonique : G–B–D–F = G7. La tierce passe de Bb à B naturel, ce qui crée la sensible et permet la résolution sur Cm." },
  { q:"La formule de la gamme mineure harmonique est :", opts:["T–T–½–T–T–T–½","T–½–T–T–½–T–T","T–½–T–T–½–1½–½","½–T–T–T–½–T–T"], a:2, fb:"T–½–T–T–½–1½–½ : le 1½ ton (ton et demi) entre le VIe et VIIe degrés est caractéristique de la mineure harmonique — un grand saut mélodique qui lui donne sa couleur orientale." },

  // Emprunts
  { q:"Qu'est-ce qu'un emprunt harmonique ?", opts:["Un accord joué deux fois","Un accord issu d'une tonalité différente, utilisé temporairement","Un renversement inhabituel","Une modulation permanente"], a:1, fb:"Un emprunt consiste à utiliser momentanément un accord d'une autre tonalité — sans quitter la tonalité principale. La fonction reste identifiable grâce au triton fonctionnel." },
  { q:"Pourquoi C majeur et C mineur partagent-ils le même triton fonctionnel ?", opts:["Par hasard","Car ils ont la même tonique et le triton F–B est commun aux deux gammes","Car ils ont les mêmes notes","Car la sensible est identique"], a:1, fb:"F et B (Fa et Si) sont présents dans les deux tonalités — ce triton détermine les fonctions harmoniques. C'est pourquoi les accords des deux tonalités peuvent être échangés sans briser la logique fonctionnelle." },
  { q:"Quel accord de C mineur peut remplacer F (IVe degré) en C majeur ?", opts:["Cm","Fm","Ab","Eb"], a:1, fb:"Fm est la sous-dominante de C mineur. Comme F, elle a la fonction sous-dominante (contient Fa mais pas Si). Fm peut donc remplacer F en C majeur — emprunt très expressif." },
  { q:"La progression C–Fm–C est un exemple de :", opts:["Modulation en C mineur","Emprunt du IVe degré mineur","Cadence rompue","Cycle des quintes"], a:1, fb:"C (tonique) → Fm (sous-dominante empruntée à C mineur) → C (tonique). Le Fm est un emprunt — on reste en C majeur mais on colore la phrase avec une teinte mineure." },
  { q:"Quelle est la fonction de Ab (Lab majeur) en C majeur ?", opts:["Dominante","Sous-dominante","Tonique (emprunté à C mineur)","Modulante"], a:2, fb:"Ab est le VIe degré de C mineur. Il a la fonction tonique (ne contient ni Fa ni Si). En C majeur, il remplace Am comme substitut tonique — emprunt expressif et lumineux." },
  { q:"L'accord Eb (Mib majeur) emprunté en C majeur a la fonction :", opts:["Dominante","Sous-dominante","Tonique","Aucune — il est hors tonalité"], a:2, fb:"Eb est le IIIe degré de C mineur — fonction tonique. En C majeur, il remplace Em. Très utilisé dans le rock (I–bIII–IV–I) pour sa couleur ample et massive." },
  { q:"Pour déterminer la fonction d'un accord emprunté, on utilise :", opts:["Sa fondamentale","Le triton fonctionnel de la tonalité principale","Sa position dans la gamme mineure","Son nombre de notes"], a:1, fb:"Le triton fonctionnel (F–B en C majeur/mineur) est le repère universel. S'il contient F+B → dominante. F seul → sous-dominante. Ni l'un ni l'autre → tonique." },
  { q:"La progression C–Fm–C–G7–C utilise Fm comme :", opts:["Dominante","Substitut de Em","Sous-dominante empruntée","Accord de passage"], a:2, fb:"Fm a la fonction sous-dominante (contient Fa). Il prépare G7 (dominante) puis C (tonique) = SD–D–T. L'emprunt colore la phrase sans briser la logique fonctionnelle." },

  // Suites classiques
  { q:"Quel principe relie les accords dans le cycle des quintes descendantes ?", opts:["Chaque accord monte d'une tierce","Chaque accord descend d'une quinte (ou monte d'une quarte)","Chaque accord est renversé","Chaque accord est à l'état fondamental"], a:1, fb:"Le cycle des quintes descendantes : chaque fondamentale est une quinte sous la précédente. Ce mouvement crée une attraction naturelle — la dynamique la plus forte de l'harmonie tonale." },
  { q:"Quel célèbre standard de jazz est basé sur le cycle des quintes en mineur ?", opts:["All The Things You Are","Autumn Leaves","Misty","Round Midnight"], a:1, fb:"Autumn Leaves utilise le cycle des quintes descendantes en G mineur (et Bb majeur) — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. C'est l'exemple pédagogique classique." },
  { q:"La basse de chaconne descend typiquement :", opts:["Par quintes","Par degrés conjoints ou par tierces depuis I vers V","Par secondes augmentées","Par octaves"], a:1, fb:"La basse de chaconne crée une ligne descendante conjoncte ou par tierces — Do → Si♭ → La♭ → Sol en C mineur. Cette basse est un ostinato sur lequel se développent des variations." },
  { q:"Dans la basse de chaconne, on utilise exceptionnellement la gamme mineure :", opts:["Harmonique sur tous les degrés","Naturelle sur le Ve degré (Gm au lieu de G7)","Majeure sur le IIIe degré","Dorique sur le VIe degré"], a:1, fb:"Dans la basse de chaconne, on utilise la mineure naturelle sur le Ve degré pour fluidifier la ligne descendante. L'exception Gm est spécifique à ce contexte." },
  { q:"L'accord napolitain est le degré :", opts:["♭III en premier renversement","♭II en accord majeur, souvent en premier renversement","IV abaissé","VIIe augmenté"], a:1, fb:"Le napolitain = ♭II majeur. En C mineur : Db majeur. Il est généralement présenté en 1er renversement (♭II6) avec la tierce à la basse." },
  { q:"La fonction harmonique de l'accord napolitain est :", opts:["Dominante","Tonique","Sous-dominante","Neutre"], a:2, fb:"Le napolitain a la fonction sous-dominante. En C mineur, Db contient Fa (IVe degré) mais pas Si. Il prépare la dominante : ♭II6 → V7 → I." },
  { q:"En C mineur, l'accord napolitain est :", opts:["Ab majeur","Db majeur / F","Bb majeur","Eb majeur"], a:1, fb:"Le ♭II de C est Db (Réb majeur). En premier renversement : Db/F. C'est l'accord napolitain de C mineur." },
  { q:"Quelle couleur expressive caractérise l'accord napolitain ?", opts:["Joyeuse et légère","Dramatique et pathétique","Mystérieuse et modale","Neutre et stable"], a:1, fb:"Le demi-ton entre le ♭II et la tonique (Réb → Do) est chargé d'expressivité dramatique. On retrouve le napolitain chez Beethoven, Chopin, et dans la musique de film pour évoquer la gravité ou le destin." },
  { q:"Le schéma classique d'utilisation du napolitain est :", opts:["♭II → I → V","♭II6 → V7 → I","I → ♭II → I","V → ♭II → V"], a:1, fb:"♭II6 → V7 → I : le napolitain prépare la dominante comme une sous-dominante renforcée, puis la dominante résout sur la tonique. Schéma très fréquent chez les romantiques." },
  { q:"Dans le cycle des quintes en C mineur, quel accord suit Fm7 ?", opts:["Cm","Bdim7","G7","EbMaj7"], a:1, fb:"Cm → Fm7 → Bdim7 → EbMaj7... Le Bdim7 est une quinte en dessous de Fm (Fa → Si). C'est le VIIe degré de C mineur harmonique." },

  // Analyse et application
  { q:"La progression Am–F–C–G en A mineur emprunte F depuis :", opts:["A majeur","C majeur","La mineure harmonique","F majeur"], a:0, fb:"En A mineur, le VIe degré naturel est Fa. F est le VIe degré de A mineur naturel — pas un emprunt ici. F appartient diatoniquement à la gamme de A mineur naturelle." },
  { q:"La progression C–Bb–F–C en C majeur emprunte Bb depuis :", opts:["G majeur","C mineur","F majeur","Bb majeur"], a:2, fb:"Bb (Sib majeur) n'appartient pas à C majeur. C'est le VIIe degré de F majeur, ou le VIIe degré de C mineur naturel. En C majeur, c'est un emprunt — souvent utilisé dans le rock (I–bVII–IV–I)." },
  { q:"Quelle progression illustre le mieux l'emprunt IV mineur en majeur ?", opts:["C–F–G7–C","C–Fm–G7–C","C–Dm–G7–C","C–Am–G7–C"], a:1, fb:"C–Fm–G7–C : le Fm est emprunté à C mineur. C'est l'emprunt du IVe degré mineur en contexte majeur — couleur sombre sur la sous-dominante, très romantique." },
  { q:"En G majeur, l'accord napolitain serait :", opts:["Ab majeur","Ab majeur / C","Eb majeur","F majeur"], a:1, fb:"Le ♭II de G est Ab (Lab). En premier renversement avec C (Do) à la basse : Ab/C. C'est le napolitain de G majeur." },
  { q:"Pourquoi le cycle des quintes est-il si naturel à l'oreille ?", opts:["Car il évite toutes les dissonances","Car le mouvement de quinte est la consonance la plus pure après l'octave","Car il reste dans la même gamme","Car il utilise toujours des accords majeurs"], a:1, fb:"La quinte juste (rapport 3/2) est la consonance la plus fondamentale après l'octave. Une descente de quinte crée une attraction acoustique naturelle — c'est pourquoi ce mouvement sonne si inévitable." },
  { q:"Un emprunt est différent d'une modulation car :", opts:["L'emprunt utilise des accords renversés","L'emprunt est momentané — on ne quitte pas la tonalité principale","L'emprunt est toujours suivi d'une cadence parfaite","L'emprunt utilise toujours le napolitain"], a:1, fb:"Un emprunt est une couleur passagère — un accord étranger intégré sans déplacer le centre tonal. La modulation installe durablement une nouvelle tonalité avec sa propre cadence." },
  { q:"La progression C–Ab–Bb–C en C majeur utilise :", opts:["Deux cadences parfaites","Deux emprunts à C mineur (Ab et Bb)","Une modulation en Ab majeur","Une basse de chaconne"], a:1, fb:"Ab (Lab) et Bb (Sib) sont empruntés à C mineur naturel. Cette progression (I–bVI–bVII–I) est typique du rock — deux emprunts qui créent une couleur modale et massive." },

  // ── Gamme mineure — approfondissement ──
  { q:"Pourquoi la gamme mineure naturelle est-elle issue du VIe degré de la gamme majeure ?", opts:["Par convention historique arbitraire","Car en partant du VIe degré on obtient la même séquence T/½ décalée","Car c'est la gamme avec le moins d'altérations","Car le VIe degré est toujours mineur"], a:1, fb:"La gamme majeure commence sur le Ier degré. Si on reprend la même séquence de tons/demi-tons à partir du VIe, on obtient la gamme mineure relative — mêmes notes, point de départ différent." },
  { q:"En A mineur naturel, quelles notes sont identiques à C majeur ?", opts:["6 notes sur 7","7 notes sur 7 — exactement les mêmes","5 notes sur 7","Aucune note en commun"], a:1, fb:"Am naturel et C majeur partagent exactement les 7 mêmes notes — A B C D E F G. Am est le relatif mineur de C majeur." },
  { q:"En C mineur harmonique, quelle note est altérée par rapport à la naturelle ?", opts:["Le IVe degré (Fa)","Le VIe degré (Lab)","Le VIIe degré (Si♭ → Si naturel)","Le IIe degré (Ré)"], a:2, fb:"La mineure harmonique élève le VIIe degré d'un demi-ton : Si♭ (Bb) devient Si naturel (B). Cela crée la sensible et le triton fonctionnel." },
  { q:"L'intervalle caractéristique de la gamme mineure harmonique est :", opts:["La tierce augmentée entre I et III","Le triton entre IV et VII","Le ton et demi entre VI et VII","La seconde diminuée entre V et VI"], a:2, fb:"Entre le VIe (Lab) et le VIIe élevé (Si naturel) en C mineur harmonique, il y a 1 ton et demi (3 demi-tons). Cet intervalle est la signature sonore de la mineure harmonique — couleur parfois qualifiée d'orientale." },
  { q:"Quel est le Ve degré en C mineur naturel ?", opts:["Gm","G7","G majeur","Gdim"], a:0, fb:"En C mineur naturel, le VIIe degré est Bb (non altéré). L'accord sur Sol est G–Bb–D = Gm. Sans la sensible, il n'y a pas de tension vers Cm." },
  { q:"Pourquoi utilise-t-on la mineure naturelle sur le Ier degré plutôt que l'harmonique ?", opts:["Par tradition","Car la mineure harmonique créerait Cm avec une 7e majeure (ImMaj7) — accord instable","Car la mineure naturelle est plus belle","Car le Ier degré n'a pas besoin de triton"], a:1, fb:"Sur le Ier degré avec mineure harmonique : C–Eb–G–B = CmMaj7. La 7e majeure sur la tonique est très instable. On préfère la mineure naturelle pour garder Cm ou Cm7 comme tonique stable." },
  { q:"En D mineur harmonique, quelle note est élevée ?", opts:["Sol (G)","Do (C)","Do# (C#)","Fa# (F#)"], a:2, fb:"D mineur naturel : D E F G A Bb C. La mineure harmonique élève le VIIe degré C → C#. D mineur harmonique : D E F G A Bb C#." },
  { q:"En E mineur harmonique, la sensible est :", opts:["Ré (D)","Ré# (D#)","Fa (F)","Sol (G)"], a:1, fb:"E mineur naturel a D comme VIIe degré. La mineure harmonique l'élève : D → D#. La sensible de E mineur harmonique est D#." },

  // ── Emprunts — approfondissement ──
  { q:"En G majeur, quel accord est emprunté dans la progression G–Eb–Bb–G ?", opts:["Aucun","Eb et Bb, empruntés à G mineur","Seulement Bb","Seulement Eb"], a:1, fb:"En G majeur, Eb (Mib) et Bb (Sib) n'appartiennent pas à la gamme. Ils sont empruntés à G mineur. La progression G–bVI–bVII–G est typique du rock." },
  { q:"En D majeur, Bb est un emprunt de :", opts:["D mineur","G majeur","A majeur","F majeur"], a:0, fb:"En D mineur, le VIe degré est Bb (Sib). Ce n'est pas une note de D majeur — c'est un emprunt à D mineur en contexte de D majeur." },
  { q:"Quel emprunt est le plus fréquent dans la musique classique et romantique ?", opts:["Le bVII","Le bVI","Le IV mineur (bIV)","Le bII"], a:2, fb:"L'emprunt du IVe degré mineur (IV mineur) est parmi les plus fréquents — F → Fm en C majeur. Il apporte une couleur sombre et expressive sur la sous-dominante, très prisée du romantisme." },
  { q:"Dans la progression A–F–C–G, F est :", opts:["Un emprunt à A mineur","Diatonique à A majeur","Un accord de dominante secondaire","Un accord napolitain"], a:1, fb:"A majeur : A B C# D E F# G#. F naturel n'appartient pas à A majeur. En revanche, F est le VIe degré de A mineur — c'est un emprunt." },
  { q:"L'emprunt I mineur (ex : Cm en C majeur) a la même fonction que :", opts:["Am","F","G7","Em"], a:0, fb:"Cm et Am ont tous deux la fonction tonique (aucun ne contient F ni B, le triton de C). Cm peut donc remplacer Am comme tonique alternative, avec une couleur plus sombre." },
  { q:"En C majeur, quelle est la fonction de Bb majeur ?", opts:["Dominante","Sous-dominante","Tonique","Il n'a pas de fonction claire"], a:1, fb:"Bb (Sib majeur) contient Fa (F) mais pas Si (B). Fa seul sans Si = fonction sous-dominante. Bb peut donc remplacer F ou Dm dans une progression SD–D–T." },
  { q:"La progression C–Cm–C est un exemple de :", opts:["Modulation","Pendule","Minorisation momentanée (I → Im)","Cadence plagale"], a:2, fb:"C → Cm → C : on minorise momentanément la tonique — même fondamentale, mais la tierce passe de E à Eb. Technique très expressive, utilisée dans les codas et les moments dramatiques." },
  { q:"En E majeur, l'emprunt le plus fréquent en rock est :", opts:["Cm","Bm","D (bVII emprunté à E mineur)","Ab"], a:2, fb:"D majeur (Ré) est le bVII de E majeur — emprunté à E mineur. La progression E–D–A–E est classique du rock (ex. : nombreux morceaux de Led Zeppelin, Rolling Stones)." },
  { q:"La progression I–bVII–IV–I en C majeur est :", opts:["C–Bb–F–C","C–Bb–G–C","C–Ab–F–C","C–Bb–Dm–C"], a:0, fb:"C (I) – Bb (bVII, emprunté à C mineur) – F (IV) – C (I). Bb est l'emprunt du VIIe degré mineur. C–Bb–F–C est une progression iconique du rock." },
  { q:"Quel accord emprunté à C mineur remplace Em (IIIe degré) en C majeur ?", opts:["Cm","Eb","Ab","Fm"], a:1, fb:"Eb (Mib majeur) est le IIIe degré de C mineur. Il remplace Em avec une couleur plus large et massive. La progression C–Eb–F–G est courante en rock et pop." },
  { q:"Pourquoi peut-on échanger des accords entre tonalités homonymes ?", opts:["Car ils ont les mêmes notes","Car ils partagent le triton fonctionnel et donc les mêmes fonctions","Car ils sont dans la même armure","Car la mélodie reste identique"], a:1, fb:"C majeur et C mineur partagent F et B (le triton fonctionnel). Les fonctions sont déterminées par rapport à ce triton — les accords des deux tonalités peuvent donc être échangés librement." },

  // ── Cycle des quintes — approfondissement ──
  { q:"Le cycle des quintes complet en C majeur est :", opts:["C–F–Bdim–Em–Am–Dm–G7–C","C–G–Dm–Am–Em–Bdim–F–C","C–Dm–Em–F–G–Am–Bdim–C","C–Am–F–Dm–Bdim–G7–Em–C"], a:0, fb:"C → F → Bdim → Em → Am → Dm → G7 → C. Chaque accord est une quinte en dessous du précédent dans la gamme de C majeur." },
  { q:"En A mineur, le cycle des quintes commence par :", opts:["Am–Dm–G7–CMaj7–FMaj7–Bm7b5–E7–Am","Am–E7–Dm–G7–CMaj7–Am","Am–Dm–G7–Am","Am–G7–Dm–Am"], a:0, fb:"Am → Dm → G7 → CMaj7 → FMaj7 → Bm7b5 → E7 → Am. Même principe qu'en mineur — chaque accord descend d'une quinte diatonique." },
  { q:"Pourquoi le cycle des quintes descendantes est-il harmoniquement si efficace ?", opts:["Car il évite les dissonances","Car chaque fondamentale attire la suivante par le mouvement de quinte — la plus forte attraction de basse","Car il reste dans une seule gamme","Car il utilise toujours des accords majeurs"], a:1, fb:"Le mouvement de quinte descendante (ou quarte ascendante) à la basse crée l'attraction la plus naturelle de l'harmonie tonale — c'est la même logique qui fait que V résout vers I." },
  { q:"Dans Autumn Leaves, le cycle de quintes passe alternativement de :", opts:["C majeur à G majeur","C mineur à Eb majeur","G mineur à Bb majeur — relatif mineur et majeur","A mineur à C majeur"], a:2, fb:"Autumn Leaves est en G mineur / Bb majeur (relatifs). Le cycle passe : Cm7–F7–BbMaj7–EbMaj7 (en Bb majeur) puis Am7b5–D7–Gm (en G mineur)." },
  { q:"Quel accord complète la séquence Cm–Fm7–Bdim7–… dans le cycle en C mineur ?", opts:["G7","AbMaj7","EbMaj7","Dm7b5"], a:2, fb:"Cm → Fm7 → Bdim7 → EbMaj7 → AbMaj7 → Dm7b5 → G7 → Cm. Après Bdim7, on descend d'une quinte : Si → Mi♭ = EbMaj7." },
  { q:"Le cycle des quintes en mode majeur omet souvent les IIIe et VIIe degrés car :", opts:["Ils sont trop graves","Ils sont moins utilisés et leur fonction est ambiguë","Ils ne sont pas dans la gamme","Ils créent des octaves parallèles"], a:1, fb:"Em (IIIe) et Bdim (VIIe) sont harmoniquement plus complexes et moins fréquents dans les progressions courantes. En pratique, le cycle majeur raccourci est souvent I–IV–V–I." },

  // ── Chaconne — approfondissement ──
  { q:"La basse de chaconne est principalement utilisée comme :", opts:["Une progression de 8 accords","Un ostinato servant de base aux variations","Une suite de cadences parfaites","Un cycle des quintes en mineur"], a:1, fb:"La basse de chaconne est un ostinato — une figure de basse répétée indéfiniment sur laquelle le compositeur construit des variations mélodiques, rythmiques et harmoniques." },
  { q:"Quel grand compositeur baroque a écrit l'une des chaconnes les plus célèbres pour violon seul ?", opts:["Vivaldi","Handel","Purcell","Bach"], a:3, fb:"La Chaconne de la Partita n°2 en Ré mineur de J.S. Bach est l'une des œuvres les plus monumentales pour violon seul — une série de variations sur une basse de chaconne." },
  { q:"La basse de chaconne crée une tension progressive car :", opts:["Elle monte vers l'aigu","Elle descend vers la dominante, créant une attente de résolution","Elle reste sur la tonique","Elle utilise des accords diminués"], a:1, fb:"La basse descend par degrés (Do → Si♭ → La♭ → Sol en C mineur) puis arrive sur Sol (dominante), qui appelle la résolution vers Cm. C'est une tension construite par le mouvement mélodique de la basse." },
  { q:"Quel accord de la basse de chaconne utilise exceptionnellement la mineure naturelle ?", opts:["Le Ier degré","Le IVe degré","Le Ve degré (Gm au lieu de G7)","Le VIe degré"], a:2, fb:"Dans la basse de chaconne, le Ve degré utilise la mineure naturelle (Gm) pour fluidifier la ligne de basse descendante. Le G7 harmonique serait plus tendu mais moins naturel dans ce contexte mélodique." },
  { q:"La progression Cm–Gm/Bb–Fm/Ab–G7 est une basse de chaconne. La basse joue :", opts:["Do–Sol–Fa–Sol","Do–Si♭–La♭–Sol","Do–Mi♭–Sol–Si","Do–Ré–Mi–Fa"], a:1, fb:"La basse joue : Do (C) sur Cm → Si♭ (Bb) sur Gm/Bb → La♭ (Ab) sur Fm/Ab → Sol (G) sur G7. Ligne descendante conjoncte caractéristique." },
  { q:"Quel élément musical moderne est directement issu de la tradition de la chaconne ?", opts:["Le chorus au jazz","La basse ostinato dans le blues et le funk","La modulation en pivot","L'accord napolitain en pop"], a:1, fb:"La basse ostinato du blues (12-bar blues) et du funk sont des descendants directs de la chaconne baroque — une basse répétée sur laquelle se développent les variations mélodiques et rythmiques." },

  // ── Napolitain — approfondissement ──
  { q:"En G mineur, l'accord napolitain est :", opts:["Eb/G","Ab/C","Ab majeur","Db majeur"], a:1, fb:"Le ♭II de G est Ab (Lab majeur). En premier renversement avec C à la basse : Ab/C. C'est l'accord napolitain de G mineur." },
  { q:"En D mineur, l'accord napolitain est :", opts:["Eb majeur","Eb/G","Bb majeur","Gb majeur"], a:1, fb:"Le ♭II de D est Eb (Mib majeur). En premier renversement avec G à la basse : Eb/G. L'accord napolitain de D mineur est Eb/G." },
  { q:"Le napolitain est généralement présenté en premier renversement parce que :", opts:["C'est plus facile à jouer","La tierce à la basse crée un mouvement conjoint plus fluide vers la dominante","Il sonne plus fort","Par convention historique sans raison acoustique"], a:1, fb:"En premier renversement (♭II6), la basse est la tierce du ♭II. Ce voix descend d'un demi-ton vers la sensible de la dominante — mouvement conjoint très expressif et naturel." },
  { q:"Le demi-ton entre le ♭II et la tonique crée une tension car :", opts:["C'est un intervalle rare","La proximité engendre une forte attraction — comme la sensible vers la tonique","Le ♭II est toujours instable","Les deux notes sont distantes de 7 demi-tons"], a:1, fb:"Réb → Do (Db → C) est un mouvement de demi-ton descendant chargé d'expressivité. Comme la sensible (B → C), cette proximité crée une attraction intense — c'est l'essence du pathos romantique." },
  { q:"Beethoven utilise le napolitain dans :", opts:["La Sonate au Clair de Lune (op.27)","La 9e Symphonie","Les deux"], a:0, fb:"La Sonate au Clair de Lune (op.27 n°2) utilise l'accord napolitain de façon caractéristique. Beethoven y recourt fréquemment pour accentuer le caractère dramatique." },
  { q:"Le napolitain peut aussi apparaître en mode majeur. En C majeur, il serait :", opts:["Ab majeur","Db majeur / F","Gb majeur","Bb majeur"], a:1, fb:"Même en C majeur, le napolitain est Db/F. Son utilisation est plus rare en majeur car il crée un contraste plus brutal, mais il reste possible avec un effet très dramatique." },
  { q:"Après le napolitain, quel accord arrive presque toujours ?", opts:["La tonique (I)","La sous-dominante (IV)","La dominante (V ou V7)","Le VIe degré"], a:2, fb:"Le napolitain prépare la dominante : ♭II6 → V7. Puis la dominante résout sur I. L'accord napolitain est une forme de prédominante — il ne résout jamais directement sur I sans passer par V." },
  { q:"Quelle note du napolitain descend d'un demi-ton vers la sensible de la dominante ?", opts:["La fondamentale du ♭II","La tierce du ♭II (qui est à la basse en ♭II6)","La quinte du ♭II","Aucune — le napolitain monte"], a:1, fb:"En C mineur, ♭II6 = Db/F. La basse F (Fa) descend d'un demi-ton vers E (Mi) — la tierce de G7. Ce mouvement de voix est l'une des résolutions les plus expressives de l'harmonie tonale." },

  // ── Analyse comparative ──
  { q:"Quelle est la différence fondamentale entre un emprunt et une modulation ?", opts:["L'emprunt est plus court","L'emprunt est momentané et ne déplace pas le centre tonal ; la modulation installe durablement une nouvelle tonalité","L'emprunt utilise le napolitain","La modulation utilise le cycle des quintes"], a:1, fb:"Un emprunt = une couleur passagère. Une modulation = un voyage : on quitte réellement la tonalité de départ et on installe un nouveau centre tonal avec sa propre cadence." },
  { q:"Lequel de ces outils est le plus dramatique harmoniquement ?", opts:["L'emprunt du IVe mineur","La basse de chaconne","L'accord napolitain","Le cycle des quintes"], a:2, fb:"L'accord napolitain (♭II6) est le plus dramatique — son demi-ton caractéristique, sa couleur étrangère à la tonalité et sa résolution via la dominante créent une tension pathétique incomparable." },
  { q:"Lequel de ces outils crée le plus d'unité et de continuité dans une phrase ?", opts:["L'accord napolitain","Le cycle des quintes descendantes","L'emprunt du bVII","La minorisation de la tonique"], a:1, fb:"Le cycle des quintes crée une chaîne d'attractions naturelles — chaque accord appelle le suivant de façon organique. Il donne à la phrase une direction claire et une continuité sans rupture." },
  { q:"La progression C–Fm–G7–C utilise Fm comme :", opts:["Dominante","Tonique empruntée","Sous-dominante empruntée à C mineur","Accord napolitain"], a:2, fb:"Fm a la fonction sous-dominante (contient Fa mais pas Si). C'est le IVe degré de C mineur — un emprunt classique. C–Fm–G7–C = T–SD empruntée–D–T." },
  { q:"La progression Db/F–G7–Cm est :", opts:["Un cycle des quintes en C mineur","Un napolitain ♭II6–V7–I en C mineur","Un emprunt de Db majeur à C majeur","Une basse de chaconne"], a:1, fb:"Db/F = accord napolitain de C mineur (♭II en 1er renversement). G7 = dominante. Cm = tonique. C'est le schéma classique ♭II6 → V7 → I." },
  { q:"Parmi ces progressions, laquelle est une basse de chaconne ?", opts:["Cm–Fm7–Bdim7–G7","Cm–Gm/Bb–Fm/Ab–G7","C–Ab–Eb–Bb","Cm–Db–G7–Cm"], a:1, fb:"Cm–Gm/Bb–Fm/Ab–G7 : la basse joue Do–Si♭–La♭–Sol, une descente conjoncte caractéristique de la chaconne. Les accords en renversement suivent la ligne de basse mélodique." },
  { q:"Lequel de ces trois éléments appartient exclusivement à la tradition baroque ?", opts:["L'accord napolitain","L'emprunt à l'homonyme","La basse de chaconne comme structure ostinato de variations","Le cycle des quintes"], a:2, fb:"La basse de chaconne comme structure formelle (thème de basse + variations) est un genre spécifiquement baroque. Le napolitain et les emprunts existent dans toutes les périodes ; le cycle des quintes est universel." },
  { q:"En jazz, le cycle des quintes est appliqué aux accords de septième. En C, cela donne :", opts:["CMaj7–FMaj7–Bdim7–Em7–Am7–Dm7–G7–CMaj7","C7–F7–Bb7–Eb7–Ab7–Db7–Gb7–B7","CMaj7–Am7–Dm7–G7–CMaj7","Dm7–G7–CMaj7"], a:0, fb:"CMaj7–FMaj7–Bdim7–Em7–Am7–Dm7–G7–CMaj7 : le cycle des quintes diatoniques complet en C majeur avec les tétrades. C'est la base harmonique de nombreux standards de jazz." },
  { q:"L'accord Bb/D dans une progression en C majeur est :", opts:["Bb en état fondamental","Bb en 1er renversement, emprunté à C mineur","Le napolitain de C","Bdim renversé"], a:1, fb:"Bb/D = Sib majeur avec Ré à la basse (1er renversement). Bb est emprunté à C mineur (VIIe degré naturel). La basse D crée un mouvement conjoint fluide dans la ligne de basse." },
  { q:"Quel est le lien entre le napolitain et la tonalité de Fa mineur en C ?", opts:["Aucun lien","Db est le VIe degré de Fa mineur — le napolitain est un emprunt indirect à F mineur","Db est la tonique de F mineur","Db est le IIe degré de F majeur"], a:1, fb:"En F mineur, Db (Réb) est le VIe degré. Utilisé en C mineur, Db peut être analysé comme un emprunt à la tonalité de F mineur — ce qui explique sa couleur particulièrement étrangère." },
  { q:"La progression Am–F–C–G est la base de nombreuses chansons pop. F et C ont ici les fonctions :", opts:["T–D","SD–T","D–SD","SD–SD"], a:1, fb:"F = sous-dominante (IVe degré de C). C = tonique (Ier degré de C). Après Am (tonique) : Am(T)–F(SD)–C(T)–G(D). La séquence complète est T–SD–T–D." },
  { q:"En A mineur harmonique, le Ve degré est :", opts:["Em","E7","Edim","E majeur"], a:1, fb:"En A mineur harmonique, le VIIe degré est G# (Sol#). L'accord construit sur Mi est E–G#–B–D = E7. La mineure harmonique crée la dominante avec sa 7e mineure." },
  { q:"Qu'est-ce que la minorisation d'un accord ?", opts:["Le jouer plus grave","Abaisser sa tierce majeure d'un demi-ton pour le rendre mineur","Le renverser","Le transposer à la quinte"], a:1, fb:"La minorisation consiste à abaisser la tierce d'un accord majeur d'un demi-ton : E → Eb transforme C en Cm. Technique de transition très expressive utilisée notamment dans les codas romantiques." },
  { q:"La progression C–C/B–Am–Am/G–F–G–C utilise :", opts:["Un cycle des quintes","Une ligne de basse descendante conjoncte (Do–Si–La–Sol–Fa–Sol–Do)","Une série d'emprunts","Une basse de chaconne baroque"], a:1, fb:"La basse joue C–B–A–G–F–G–C — une descente mélodique puis une montée vers la résolution. Ce type de basse linéaire est caractéristique de nombreuses ballades pop et rock." },

  { q:"En C mineur, quelles notes forment le triton fonctionnel ?", opts:["Do–Sol","Fa–Si (F–B)","Ré–Lab","Mi♭–Si♭"], a:1, fb:"Le triton fonctionnel de C mineur est F–B (Fa–Si), exactement comme en C majeur. C'est ce triton commun qui permet les emprunts entre les deux tonalités." },
  { q:"Pourquoi G7 est-il le même en C majeur et C mineur ?", opts:["Par coïncidence","Car G7 contient F et B — le triton commun aux deux gammes","Car G est le Ve degré des deux","Car G7 n'appartient à aucune des deux"], a:1, fb:"G7 = G–B–D–F. Il contient le triton F–B, commun à C majeur et C mineur harmonique. C'est pourquoi la dominante G7 fonctionne dans les deux tonalités — et permet les emprunts." },
  { q:"En A majeur, quel accord serait un emprunt de A mineur naturel ?", opts:["D majeur","F# mineur","F majeur","G majeur"], a:2, fb:"A mineur naturel contient F naturel (Fa). En A majeur, F est élevé en F# — F naturel est donc un emprunt à A mineur. F majeur en A majeur = bVI emprunté." },
  { q:"La couleur du bVII emprunté (ex : Bb en C) est souvent décrite comme :", opts:["Dramatique et pathétique","Modale, ample et rock","Douce et sacrée","Mystérieuse et suspendue"], a:1, fb:"Le bVII (comme Bb en C majeur) crée une couleur modale — souvent qualifiée de 'rock' ou de 'folk'. Il adoucit la tension sans créer le chromatisme intense du napolitain." },
  { q:"Quelle suite harmonique est à la base du 12-bar blues ?", opts:["Le cycle des quintes en mineur","La basse de chaconne","L'alternance I–IV–V avec répétition","Le napolitain ♭II6–V–I"], a:2, fb:"Le blues sur 12 mesures repose sur I–IV–V : 4 mesures sur I, 2 sur IV, 2 sur I, 2 sur V, 2 sur I. C'est l'extension fonctionnelle la plus simple autour de T–SD–D–T." },
  { q:"La progression Am–G–F–E7 en A mineur illustre :", opts:["Un cycle des quintes","Une descente par degrés conjoints vers la dominante","Un emprunt à C majeur","Une suite de cadences rompues"], a:1, fb:"Am(I)–G(VII)–F(VI)–E7(V) : la progression descend par degrés conjoints vers la dominante E7. E7 contient G# (sensible de A mineur harmonique) — le triton fonctionnel de A mineur." },
  { q:"Quel compositeur romantique est célèbre pour ses utilisations de l'accord napolitain ?", opts:["Bach","Mozart","Chopin","Haydn"], a:2, fb:"Chopin utilise abondamment l'accord napolitain dans ses nocturnes et ballades — notamment pour accentuer les moments de tension dramatique et de mélancolie profonde." },
  { q:"En C mineur, quelle progression résume le mieux la logique SD–D–T avec emprunts ?", opts:["C–F–G7–C","Cm–Fm–G7–Cm","Cm–Db/F–G7–Cm","Cm–G7–Fm–Cm"], a:2, fb:"Cm(T) → Db/F(napolitain, SD) → G7(D) → Cm(T). Le napolitain agit comme une sous-dominante renforcée avant la dominante — enchaînement SD–D–T en version dramatique." },
  { q:"La basse de chaconne diffère du cycle des quintes car :", opts:["Elle utilise des accords majeurs","Elle crée une ligne mélodique descendante à la basse, pas un mouvement de quinte à chaque accord","Elle est plus rapide","Elle reste toujours sur le même accord"], a:1, fb:"Le cycle des quintes est défini par un mouvement de quinte entre les fondamentales. La basse de chaconne crée une ligne mélodique conjoncte ou par tierces — l'identité vient de la basse ostinato, pas du mouvement harmonique." },
];

// English translations — add when available; until then falls back to fr


const questionsEn: Question[] = [{ q:"Why does the natural minor scale pose a harmonic problem?", opts:["It has too many notes","Its tritone does not resolve toward the tonic","It has no seventh degree","It contains too many accidentals"], a:1, fb:"In natural minor, the tritone falls between the second and sixth degrees — it does not resolve toward the first and third degrees as in major. There is no functional leading tone." },
{ q:"How does the harmonic minor scale solve this problem?", opts:["By removing the tritone","By raising the seventh degree by a half step","By lowering the fourth degree","By adding an eighth note"], a:1, fb:"Raising the seventh degree creates a strong leading tone (B natural instead of Bb in C minor) and restores a functional tritone between the fourth and seventh degrees — as in major." },
{ q:"What does the harmonic minor scale provide that the natural minor does not?", opts:["An extra octave","A leading tone and a functional tritone","Three new notes","A minor dominant chord"], a:1, fb:"The harmonic minor recreates the leading tone (VII → I, ascending half step) and the functional tritone (IV + VII). Without it, the dominant chord would be minor (Gm instead of G7)." },
{ q:"In C harmonic minor, which chord forms the dominant?", opts:["Gm","G","G7","Dm"], a:2, fb:"With the raised seventh degree (B natural), the chord built on G is G–B–D–F = G7. The minor seventh (F) comes from the scale; the B natural comes from the harmonic minor." },
{ q:"On which degrees is the natural minor used rather than the harmonic?", opts:["IV and V","I and III","II and VII","V and VI"], a:1, fb:"The first (tonic) and third (relative major) degrees use the natural minor to remain stable. The harmonic minor on these degrees would create overly unstable intervals (major 7th, augmented 5th)." },
{ q:"In C minor, what is the difference between Gm (natural) and G7 (harmonic)?", opts:["The root","The third","The seventh and the third — B♭ vs B natural","The fifth"], a:2, fb:"In natural minor: G–Bb–D = Gm. In harmonic minor: G–B–D–F = G7. The third changes from Bb to B natural, which creates the leading tone and allows resolution to Cm." },
{ q:"The formula for the harmonic minor scale is:", opts:["W–W–H–W–W–W–H","W–H–W–W–H–W–W","W–H–W–W–H–WH–H","H–W–W–W–H–W–W"], a:2, fb:"W–H–W–W–H–WH–H: the augmented second (one and a half steps) between the sixth and seventh degrees is characteristic of the harmonic minor — a large melodic leap that gives it its distinctive color." },

{ q:"What is a harmonic borrowing?", opts:["A chord played twice","A chord taken from a different key, used temporarily","An unusual inversion","A permanent modulation"], a:1, fb:"A borrowing consists of momentarily using a chord from another key — without leaving the main key. The function remains identifiable thanks to the functional tritone." },
{ q:"Why do C major and C minor share the same functional tritone?", opts:["By coincidence","Because they have the same tonic and the tritone F–B is common to both scales","Because they have the same notes","Because the leading tone is identical"], a:1, fb:"F and B are present in both keys — this tritone determines harmonic functions. This is why chords from both keys can be exchanged without breaking functional logic." },
{ q:"Which chord from C minor can replace F (IV degree) in C major?", opts:["Cm","Fm","Ab","Eb"], a:1, fb:"Fm is the subdominant of C minor. Like F, it has the subdominant function (contains F but not B). Fm can therefore replace F in C major — a very expressive borrowing." },
{ q:"The progression C–Fm–C is an example of:", opts:["Modulation to C minor","Borrowing of the minor fourth degree","Deceptive cadence","Circle of fifths"], a:1, fb:"C (tonic) → Fm (subdominant borrowed from C minor) → C (tonic). Fm is a borrowing — we remain in C major but color the phrase with a minor tint." },
{ q:"What is the function of Ab in C major?", opts:["Dominant","Subdominant","Tonic (borrowed from C minor)","Modulating"], a:2, fb:"Ab is the sixth degree of C minor. It has the tonic function (contains neither F nor B). In C major, it replaces Am as a tonic substitute — an expressive and luminous borrowing." },
{ q:"The chord Eb borrowed in C major has the function:", opts:["Dominant","Subdominant","Tonic","None — it is outside the key"], a:2, fb:"Eb is the third degree of C minor — tonic function. In C major, it replaces Em. Widely used in rock (I–bIII–IV–I) for its broad and massive color." },
{ q:"To determine the function of a borrowed chord, one uses:", opts:["Its root","The functional tritone of the main key","Its position in the minor scale","Its number of notes"], a:1, fb:"The functional tritone (F–B in C major/minor) is the universal reference. If it contains F+B → dominant. F alone → subdominant. Neither → tonic." },
{ q:"The progression C–Fm–C–G7–C uses Fm as:", opts:["Dominant","Substitute for Em","Borrowed subdominant","Passing chord"], a:2, fb:"Fm has the subdominant function (contains F). It prepares G7 (dominant) then C (tonic) = SD–D–T. The borrowing colors the phrase without breaking functional logic." },

{ q:"What principle connects chords in the descending cycle of fifths?", opts:["Each chord rises by a third","Each chord descends by a fifth (or rises by a fourth)","Each chord is inverted","Each chord is in root position"], a:1, fb:"The descending cycle of fifths: each root is a fifth below the previous one. This motion creates a natural attraction — the strongest driving force in tonal harmony." },
{ q:"Which famous jazz standard is based on the cycle of fifths in minor?", opts:["All The Things You Are","Autumn Leaves","Misty","Round Midnight"], a:1, fb:"Autumn Leaves uses the descending cycle of fifths in G minor (and Bb major) — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. It is the classic pedagogical example." },
{ q:"The chaconne bass typically descends:", opts:["By fifths","By stepwise motion or by thirds from I to V","By augmented seconds","By octaves"], a:1, fb:"The chaconne bass creates a descending stepwise or thirds-based line — C → Bb → Ab → G in C minor. This bass is an ostinato over which variations are developed." },
{ q:"In the chaconne bass, the minor scale used exceptionally is:", opts:["Harmonic on all degrees","Natural on the fifth degree (Gm instead of G7)","Major on the third degree","Dorian on the sixth degree"], a:1, fb:"In the chaconne bass, the natural minor is used on the fifth degree to smooth the descending line. The exception Gm is specific to this context." },
{ q:"The Neapolitan chord is degree:", opts:["♭III in first inversion","♭II as a major chord, often in first inversion","Lowered IV","Augmented VII"], a:1, fb:"The Neapolitan = ♭II major. In C minor: Db major. It is generally presented in first inversion (♭II6) with the third in the bass." },
{ q:"The harmonic function of the Neapolitan chord is:", opts:["Dominant","Tonic","Subdominant","Neutral"], a:2, fb:"The Neapolitan has the subdominant function. In C minor, Db contains F (fourth degree) but not B. It prepares the dominant: ♭II6 → V7 → I." },
{ q:"In C minor, the Neapolitan chord is:", opts:["Ab major","Db major / F","Bb major","Eb major"], a:1, fb:"The ♭II of C is Db. In first inversion: Db/F. This is the Neapolitan chord of C minor." },
{ q:"What expressive color characterizes the Neapolitan chord?", opts:["Joyful and light","Dramatic and pathetic","Mysterious and modal","Neutral and stable"], a:1, fb:"The half step between ♭II and the tonic (Db → C) is charged with dramatic expressivity. The Neapolitan appears in Beethoven, Chopin, and film music to evoke gravity or fate." },
{ q:"The classic pattern for using the Neapolitan is:", opts:["♭II → I → V","♭II6 → V7 → I","I → ♭II → I","V → ♭II → V"], a:1, fb:"♭II6 → V7 → I: the Neapolitan prepares the dominant like a reinforced subdominant, then the dominant resolves to the tonic. A very common scheme among Romantic composers." },
{ q:"In the cycle of fifths in C minor, which chord follows Fm7?", opts:["Cm","Bdim7","G7","EbMaj7"], a:1, fb:"Cm → Fm7 → Bdim7 → EbMaj7... Bdim7 is a fifth below Fm (F → B). It is the seventh degree of C harmonic minor." },

{ q:"The progression Am–F–C–G in A minor borrows F from:", opts:["A major","C major","The harmonic minor","F major"], a:0, fb:"In A minor, the natural sixth degree is F. F is the sixth degree of A natural minor — not a borrowing here. F belongs diatonically to the A natural minor scale." },
{ q:"The progression C–Bb–F–C in C major borrows Bb from:", opts:["G major","C minor","F major","Bb major"], a:2, fb:"Bb does not belong to C major. It is the seventh degree of F major, or the seventh degree of C natural minor. In C major, it is a borrowing — often used in rock (I–bVII–IV–I)." },
{ q:"Which progression best illustrates the minor IV borrowing in a major context?", opts:["C–F–G7–C","C–Fm–G7–C","C–Dm–G7–C","C–Am–G7–C"], a:1, fb:"C–Fm–G7–C: Fm is borrowed from C minor. This is the minor fourth degree borrowing in a major context — a dark color on the subdominant, very Romantic." },
{ q:"In G major, the Neapolitan chord would be:", opts:["Ab major","Ab major / C","Eb major","F major"], a:1, fb:"The ♭II of G is Ab. In first inversion with C in the bass: Ab/C. This is the Neapolitan of G major." },
{ q:"Why is the cycle of fifths so natural to the ear?", opts:["Because it avoids all dissonances","Because the motion of a fifth is the purest consonance after the octave","Because it stays in the same scale","Because it always uses major chords"], a:1, fb:"The perfect fifth (ratio 3/2) is the most fundamental consonance after the octave. A descending fifth creates a natural acoustic attraction — which is why this motion sounds so inevitable." },
{ q:"A borrowing differs from a modulation because:", opts:["The borrowing uses inverted chords","The borrowing is momentary — the main key is never left","The borrowing is always followed by a perfect cadence","The borrowing always uses the Neapolitan"], a:1, fb:"A borrowing is a passing color — a foreign chord integrated without shifting the tonal center. A modulation durably establishes a new key with its own cadence." },
{ q:"The progression C–Ab–Bb–C in C major uses:", opts:["Two perfect cadences","Two borrowings from C minor (Ab and Bb)","A modulation to Ab major","A chaconne bass"], a:1, fb:"Ab and Bb are borrowed from C natural minor. This progression (I–bVI–bVII–I) is typical of rock — two borrowings that create a modal and massive color." },

{ q:"Why is the natural minor scale derived from the sixth degree of the major scale?", opts:["By arbitrary historical convention","Because starting from the sixth degree produces the same W/H sequence shifted","Because it is the scale with the fewest accidentals","Because the sixth degree is always minor"], a:1, fb:"The major scale begins on the first degree. If we start the same whole/half-step sequence from the sixth degree, we obtain the relative minor scale — same notes, different starting point." },
{ q:"In A natural minor, which notes are identical to C major?", opts:["6 out of 7 notes","All 7 notes — exactly the same","5 out of 7 notes","No notes in common"], a:1, fb:"A natural minor and C major share exactly the same 7 notes — A B C D E F G. Am is the relative minor of C major." },
{ q:"In C harmonic minor, which note is altered compared to natural minor?", opts:["The fourth degree (F)","The sixth degree (Ab)","The seventh degree (B♭ → B natural)","The second degree (D)"], a:2, fb:"The harmonic minor raises the seventh degree by a half step: Bb becomes B natural. This creates the leading tone and the functional tritone." },
{ q:"The characteristic interval of the harmonic minor scale is:", opts:["The augmented third between I and III","The tritone between IV and VII","The augmented second between VI and VII","The diminished second between V and VI"], a:2, fb:"Between the sixth degree (Ab) and the raised seventh degree (B natural) in C harmonic minor, there is an augmented second (3 half steps). This interval is the sonic signature of the harmonic minor — a color sometimes described as oriental." },
{ q:"What is the fifth degree in C natural minor?", opts:["Gm","G7","G major","Gdim"], a:0, fb:"In C natural minor, the seventh degree is Bb (unaltered). The chord built on G is G–Bb–D = Gm. Without the leading tone, there is no tension toward Cm." },
{ q:"Why is natural minor used on the first degree rather than harmonic?", opts:["By tradition","Because harmonic minor would create Cm with a major 7th (ImMaj7) — an unstable chord","Because natural minor sounds more beautiful","Because the first degree does not need a tritone"], a:1, fb:"On the first degree with harmonic minor: C–Eb–G–B = CmMaj7. The major seventh on the tonic is very unstable. Natural minor is preferred to keep Cm or Cm7 as a stable tonic." },
{ q:"In D harmonic minor, which note is raised?", opts:["G","C","C# ","F#"], a:2, fb:"D natural minor: D E F G A Bb C. The harmonic minor raises the seventh degree C → C#. D harmonic minor: D E F G A Bb C#." },
{ q:"In E harmonic minor, the leading tone is:", opts:["D","D#","F","G"], a:1, fb:"E natural minor has D as its seventh degree. The harmonic minor raises it: D → D#. The leading tone of E harmonic minor is D#." },

{ q:"In G major, which chord is borrowed in the progression G–Eb–Bb–G?", opts:["None","Eb and Bb, borrowed from G minor","Only Bb","Only Eb"], a:1, fb:"In G major, Eb and Bb do not belong to the scale. They are borrowed from G minor. The progression G–bVI–bVII–G is typical of rock." },
{ q:"In D major, Bb is a borrowing from:", opts:["D minor","G major","A major","F major"], a:0, fb:"In D minor, the sixth degree is Bb. This note does not appear in D major — it is therefore a borrowing from D minor in a D major context." },
{ q:"Which borrowing is most common in classical and Romantic music?", opts:["The bVII","The bVI","The minor IV (bIV)","The bII"], a:2, fb:"The minor fourth degree borrowing (minor IV) is among the most common — F → Fm in C major. It brings a dark and expressive color to the subdominant, highly prized in Romanticism." },
{ q:"In the progression A–F–C–G, F is:", opts:["A borrowing from A minor","Diatonic to A major","A secondary dominant","A Neapolitan chord"], a:1, fb:"A major: A B C# D E F# G#. F natural does not belong to A major. However, F is the sixth degree of A minor — it is a borrowing." },
{ q:"The borrowing of minor I (e.g., Cm in C major) has the same function as:", opts:["Am","F","G7","Em"], a:0, fb:"Cm and Am both have the tonic function (neither contains F nor B, the tritone of C). Cm can therefore replace Am as an alternative tonic, with a darker color." },
{ q:"In C major, what is the function of Bb major?", opts:["Dominant","Subdominant","Tonic","It has no clear function"], a:1, fb:"Bb contains F but not B. F alone without B = subdominant function. Bb can therefore replace F or Dm in a SD–D–T progression." },
{ q:"The progression C–Cm–C is an example of:", opts:["Modulation","Pedal point","Momentary minorization (I → Im)","Plagal cadence"], a:2, fb:"C → Cm → C: the tonic is momentarily minorized — same root, but the third moves from E to Eb. A very expressive technique used in codas and dramatic moments." },
{ q:"In E major, the most common rock borrowing is:", opts:["Cm","Bm","D (bVII borrowed from E minor)","Ab"], a:2, fb:"D major is the bVII of E major — borrowed from E minor. The progression E–D–A–E is a rock classic (e.g., many Led Zeppelin and Rolling Stones songs)." },
{ q:"The progression I–bVII–IV–I in C major is:", opts:["C–Bb–F–C","C–Bb–G–C","C–Ab–F–C","C–Bb–Dm–C"], a:0, fb:"C (I) – Bb (bVII, borrowed from C minor) – F (IV) – C (I). Bb is the borrowing of the minor seventh degree. C–Bb–F–C is an iconic rock progression." },
{ q:"Which chord borrowed from C minor replaces Em (third degree) in C major?", opts:["Cm","Eb","Ab","Fm"], a:1, fb:"Eb is the third degree of C minor. It replaces Em with a broader and more massive color. The progression C–Eb–F–G is common in rock and pop." },
{ q:"Why can chords be exchanged between parallel keys?", opts:["Because they have the same notes","Because they share the functional tritone and therefore the same functions","Because they share the same key signature","Because the melody remains identical"], a:1, fb:"C major and C minor share F and B (the functional tritone). Functions are determined in relation to this tritone — chords from both keys can therefore be freely exchanged." },

{ q:"The complete cycle of fifths in C major is:", opts:["C–F–Bdim–Em–Am–Dm–G7–C","C–G–Dm–Am–Em–Bdim–F–C","C–Dm–Em–F–G–Am–Bdim–C","C–Am–F–Dm–Bdim–G7–Em–C"], a:0, fb:"C → F → Bdim → Em → Am → Dm → G7 → C. Each chord is a fifth below the previous one within the C major scale." },
{ q:"In A minor, the cycle of fifths begins with:", opts:["Am–Dm–G7–CMaj7–FMaj7–Bm7b5–E7–Am","Am–E7–Dm–G7–CMaj7–Am","Am–Dm–G7–Am","Am–G7–Dm–Am"], a:0, fb:"Am → Dm → G7 → CMaj7 → FMaj7 → Bm7b5 → E7 → Am. Same principle as in major — each chord descends by a diatonic fifth." },
{ q:"Why is the descending cycle of fifths harmonically so effective?", opts:["Because it avoids dissonances","Because each root attracts the next through the motion of a fifth — the strongest bass attraction in tonal harmony","Because it stays within a single scale","Because it always uses major chords"], a:1, fb:"The descending fifth (or ascending fourth) motion in the bass creates the most natural attraction in tonal harmony — it is the same logic that makes V resolve to I." },
{ q:"In Autumn Leaves, the cycle of fifths alternates between:", opts:["C major and G major","C minor and Eb major","G minor and Bb major — relative minor and major","A minor and C major"], a:2, fb:"Autumn Leaves is in G minor / Bb major (relatives). The cycle moves: Cm7–F7–BbMaj7–EbMaj7 (in Bb major) then Am7b5–D7–Gm (in G minor)." },
{ q:"Which chord completes the sequence Cm–Fm7–Bdim7–… in the cycle in C minor?", opts:["G7","AbMaj7","EbMaj7","Dm7b5"], a:2, fb:"Cm → Fm7 → Bdim7 → EbMaj7 → AbMaj7 → Dm7b5 → G7 → Cm. After Bdim7, we descend a fifth: B → Eb = EbMaj7." },
{ q:"The cycle of fifths in major mode often omits the third and seventh degrees because:", opts:["They are too low","They are less commonly used and their function is ambiguous","They are not in the scale","They create parallel octaves"], a:1, fb:"Em (III) and Bdim (VII) are harmonically more complex and less frequent in common progressions. In practice, the shortened major cycle is often I–IV–V–I." },

{ q:"The chaconne bass is primarily used as:", opts:["A progression of 8 chords","An ostinato serving as the basis for variations","A series of perfect cadences","A cycle of fifths in minor"], a:1, fb:"The chaconne bass is an ostinato — a repeated bass figure over which the composer builds melodic, rhythmic, and harmonic variations." },
{ q:"Which great Baroque composer wrote one of the most famous chaconnes for solo violin?", opts:["Vivaldi","Handel","Purcell","Bach"], a:3, fb:"The Chaconne from the Partita No. 2 in D minor by J.S. Bach is one of the most monumental works for solo violin — a series of variations over a chaconne bass." },
{ q:"The chaconne bass creates progressive tension because:", opts:["It rises toward the upper register","It descends toward the dominant, creating an expectation of resolution","It stays on the tonic","It uses diminished chords"], a:1, fb:"The bass descends by step (C → Bb → Ab → G in C minor) and arrives on G (dominant), which calls for resolution to Cm. This is a tension built through the melodic movement of the bass." },
{ q:"Which chord in the chaconne bass exceptionally uses the natural minor?", opts:["The first degree","The fourth degree","The fifth degree (Gm instead of G7)","The sixth degree"], a:2, fb:"In the chaconne bass, the fifth degree uses natural minor (Gm) to smooth the descending bass line. The harmonic G7 would be more tense but less natural in this melodic context." },
{ q:"The progression Cm–Gm/Bb–Fm/Ab–G7 is a chaconne bass. The bass plays:", opts:["C–G–F–G","C–Bb–Ab–G","C–Eb–G–B","C–D–E–F"], a:1, fb:"The bass plays: C on Cm → Bb on Gm/Bb → Ab on Fm/Ab → G on G7. A characteristic stepwise descending line." },
{ q:"Which modern musical element is directly descended from the chaconne tradition?", opts:["The jazz chorus","The ostinato bass in blues and funk","The pivot modulation","The Neapolitan chord in pop"], a:1, fb:"The ostinato bass of the blues (12-bar blues) and funk are direct descendants of the Baroque chaconne — a repeated bass over which melodic and rhythmic variations are developed." },

{ q:"In G minor, the Neapolitan chord is:", opts:["Eb/G","Ab/C","Ab major","Db major"], a:1, fb:"The ♭II of G is Ab. In first inversion with C in the bass: Ab/C. This is the Neapolitan chord of G minor." },
{ q:"In D minor, the Neapolitan chord is:", opts:["Eb major","Eb/G","Bb major","Gb major"], a:1, fb:"The ♭II of D is Eb. In first inversion with G in the bass: Eb/G. The Neapolitan chord of D minor is Eb/G." },
{ q:"The Neapolitan is generally presented in first inversion because:", opts:["It is easier to play","The third in the bass creates a smoother stepwise motion toward the dominant","It sounds louder","By historical convention without acoustic reason"], a:1, fb:"In first inversion (♭II6), the bass is the third of the ♭II. This voice descends by a half step toward the leading tone of the dominant — a very expressive and natural voice-leading motion." },
{ q:"The half step between ♭II and the tonic creates tension because:", opts:["It is a rare interval","The proximity creates a strong attraction — like the leading tone toward the tonic","The ♭II is always unstable","The two notes are seven half steps apart"], a:1, fb:"Db → C is a descending half-step motion charged with expressivity. Like the leading tone (B → C), this proximity creates intense attraction — the essence of Romantic pathos." },
{ q:"Beethoven uses the Neapolitan in:", opts:["The Moonlight Sonata (op.27)","The 9th Symphony","Both"], a:0, fb:"The Moonlight Sonata (op.27 no.2) uses the Neapolitan chord in a characteristic way. Beethoven frequently employs it to accentuate the dramatic character." },
{ q:"The Neapolitan can also appear in major mode. In C major, it would be:", opts:["Ab major","Db major / F","Gb major","Bb major"], a:1, fb:"Even in C major, the Neapolitan is Db/F. Its use is rarer in major as it creates a more abrupt contrast, but it remains possible with a very dramatic effect." },
{ q:"After the Neapolitan, which chord almost always follows?", opts:["The tonic (I)","The subdominant (IV)","The dominant (V or V7)","The sixth degree"], a:2, fb:"The Neapolitan prepares the dominant: ♭II6 → V7. Then the dominant resolves to I. The Neapolitan is a form of pre-dominant — it never resolves directly to I without passing through V." },
{ q:"Which note of the Neapolitan descends by a half step toward the leading tone of the dominant?", opts:["The root of ♭II","The third of ♭II (which is in the bass in ♭II6)","The fifth of ♭II","None — the Neapolitan moves upward"], a:1, fb:"In C minor, ♭II6 = Db/F. The bass F descends by a half step to E — the third of G7. This voice-leading motion is one of the most expressive resolutions in tonal harmony." },

{ q:"What is the fundamental difference between a borrowing and a modulation?", opts:["The borrowing is shorter","The borrowing is momentary and does not shift the tonal center; the modulation durably establishes a new key","The borrowing uses the Neapolitan","The modulation uses the cycle of fifths"], a:1, fb:"A borrowing = a passing color. A modulation = a journey: the home key is truly left and a new tonal center is established with its own cadence." },
{ q:"Which of these tools is harmonically the most dramatic?", opts:["The minor IV borrowing","The chaconne bass","The Neapolitan chord","The cycle of fifths"], a:2, fb:"The Neapolitan chord (♭II6) is the most dramatic — its characteristic half step, its foreign color, and its resolution through the dominant create an incomparable pathetic tension." },
{ q:"Which of these tools creates the most unity and continuity in a phrase?", opts:["The Neapolitan chord","The descending cycle of fifths","The bVII borrowing","Minorization of the tonic"], a:1, fb:"The cycle of fifths creates a chain of natural attractions — each chord calls the next organically. It gives the phrase a clear direction and seamless continuity." },
{ q:"The progression C–Fm–G7–C uses Fm as:", opts:["Dominant","Borrowed tonic","Subdominant borrowed from C minor","Neapolitan chord"], a:2, fb:"Fm has the subdominant function (contains F but not B). It is the fourth degree of C minor — a classic borrowing. C–Fm–G7–C = T–borrowed SD–D–T." },
{ q:"The progression Db/F–G7–Cm is:", opts:["A cycle of fifths in C minor","A Neapolitan ♭II6–V7–I in C minor","A borrowing of Db major from C major","A chaconne bass"], a:1, fb:"Db/F = Neapolitan chord of C minor (♭II in first inversion). G7 = dominant. Cm = tonic. This is the classic ♭II6 → V7 → I scheme." },
{ q:"Among these progressions, which is a chaconne bass?", opts:["Cm–Fm7–Bdim7–G7","Cm–Gm/Bb–Fm/Ab–G7","C–Ab–Eb–Bb","Cm–Db–G7–Cm"], a:1, fb:"Cm–Gm/Bb–Fm/Ab–G7: the bass plays C–Bb–Ab–G, a characteristic stepwise descent of the chaconne. The inverted chords follow the melodic bass line." },
{ q:"Which of these three elements belongs exclusively to the Baroque tradition?", opts:["The Neapolitan chord","Borrowing from the parallel key","The chaconne bass as an ostinato structure for variations","The cycle of fifths"], a:2, fb:"The chaconne bass as a formal structure (bass theme + variations) is a specifically Baroque genre. The Neapolitan and borrowings exist in all periods; the cycle of fifths is universal." },
{ q:"In jazz, the cycle of fifths is applied to seventh chords. In C, this gives:", opts:["CMaj7–FMaj7–Bdim7–Em7–Am7–Dm7–G7–CMaj7","C7–F7–Bb7–Eb7–Ab7–Db7–Gb7–B7","CMaj7–Am7–Dm7–G7–CMaj7","Dm7–G7–CMaj7"], a:0, fb:"CMaj7–FMaj7–Bdim7–Em7–Am7–Dm7–G7–CMaj7: the complete diatonic cycle of fifths in C major with tetrads. This is the harmonic foundation of many jazz standards." },
{ q:"The chord Bb/D in a progression in C major is:", opts:["Bb in root position","Bb in first inversion, borrowed from C minor","The Neapolitan of C","Bdim inverted"], a:1, fb:"Bb/D = Bb major with D in the bass (first inversion). Bb is borrowed from C minor (natural seventh degree). The bass D creates a smooth stepwise motion in the bass line." },
{ q:"What is the connection between the Neapolitan and the key of F minor in C?", opts:["No connection","Db is the sixth degree of F minor — the Neapolitan is an indirect borrowing from F minor","Db is the tonic of F minor","Db is the second degree of F major"], a:1, fb:"In F minor, Db is the sixth degree. Used in C minor, Db can be analyzed as a borrowing from F minor — which explains its particularly foreign color." },
];

const questionsEs: Question[] = [{ q:"¿Por qué la escala menor natural presenta un problema armónico?", opts:["Tiene demasiadas notas","Su tritono no se dirige hacia la tónica","No tiene un VIIe grado","Contiene demasiadas alteraciones"], a:1, fb:"En menor natural, el tritono se encuentra entre el IIe y el VIe grado — no resuelve hacia el Ie y IIIe grados como en mayor. No hay sensible funcional." },
{ q:"¿Cómo resuelve la escala menor armónica este problema?", opts:["Eliminando el tritono","Elevando el VIIe grado un semitono","Bajando el IVe grado","Añadiendo una 8ª nota"], a:1, fb:"Elevar el VIIe grado crea una sensible fuerte (B natural en lugar de Bb en C menor) y restablece un tritono funcional entre el IVe y VIIe grados — como en mayor." },
{ q:"¿Qué aporta la escala menor armónica que no tiene la natural?", opts:["Una octava adicional","Una sensible y un tritono funcional","Tres notas nuevas","Un acorde de dominante menor"], a:1, fb:"La menor armónica recrea la sensible (VII → I, semitono ascendente) y el tritono funcional (IV + VII). Sin eso, el acorde de dominante sería menor (Gm en lugar de G7)." },
{ q:"En C menor armónico, ¿qué acorde forma la dominante?", opts:["Gm","G","G7","Dm"], a:2, fb:"Con el VIIe grado elevado (B natural), el acorde construido sobre Sol es G–B–D–F = G7. La séptima menor (F) proviene de la escala, el B natural viene de la menor armónica." },
{ q:"¿En qué grados se utiliza la menor natural en lugar de la armónica?", opts:["IVe y Ve","Ie y IIIe","IIe y VIIe","Ve y VIe"], a:1, fb:"Los grados Ie (tónica) y IIIe (relativo mayor) utilizan la menor natural para mantenerse estables. La menor armónica en estos grados crearía intervalos demasiado inestables (7ª mayor, 5ª aumentada)." },
{ q:"En C menor, ¿cuál es la diferencia entre Gm (natural) y G7 (armónico)?", opts:["La fundamental","La tercera","La séptima y la tercera — B♭ vs B natural","La quinta"], a:2, fb:"En menor natural: G–Bb–D = Gm. En menor armónica: G–B–D–F = G7. La tercera pasa de Bb a B natural, lo que crea la sensible y permite la resolución sobre Cm." },
{ q:"La fórmula de la escala menor armónica es:", opts:["T–T–½–T–T–T–½","T–½–T–T–½–T–T","T–½–T–T–½–1½–½","½–T–T–T–½–T–T"], a:2, fb:"T–½–T–T–½–1½–½: el 1½ tono (tono y medio) entre el VIe y VIIe grados es característico de la menor armónica — un gran salto melódico que le da su color oriental." },

{ q:"¿Qué es un préstamo armónico?", opts:["Un acorde tocado dos veces","Un acorde proveniente de una tonalidad diferente, utilizado temporalmente","Una inversión inusual","Una modulación permanente"], a:1, fb:"Un préstamo consiste en utilizar momentáneamente un acorde de otra tonalidad — sin abandonar la tonalidad principal. La función sigue siendo identificable gracias al tritono funcional." },
{ q:"¿Por qué C mayor y C menor comparten el mismo tritono funcional?", opts:["Por casualidad","Porque tienen la misma tónica y el tritono F–B es común a ambas escalas","Porque tienen las mismas notas","Porque la sensible es idéntica"], a:1, fb:"F y B (Fa y Si) están presentes en ambas tonalidades — este tritono determina las funciones armónicas. Por eso los acordes de ambas tonalidades pueden intercambiarse sin romper la lógica funcional." },
{ q:"¿Qué acorde de C menor puede reemplazar a F (IVe grado) en C mayor?", opts:["Cm","Fm","Ab","Eb"], a:1, fb:"Fm es la subdominante de C menor. Como F, tiene función de subdominante (contiene Fa pero no Si). Fm puede por tanto reemplazar a F en C mayor — préstamo muy expresivo." },
{ q:"La progresión C–Fm–C es un ejemplo de:", opts:["Modulación a C menor","Préstamo del IVe grado menor","Cadencia rota","Ciclo de quintas"], a:1, fb:"C (tónica) → Fm (subdominante prestada de C menor) → C (tónica). El Fm es un préstamo — se permanece en C mayor pero se colorea la frase con un tinte menor." },
{ q:"¿Cuál es la función de Ab (Lab mayor) en C mayor?", opts:["Dominante","Subdominante","Tónica (prestado de C menor)","Modulante"], a:2, fb:"Ab es el VIe grado de C menor. Tiene función de tónica (no contiene ni Fa ni Si). En C mayor, reemplaza a Am como sustituto de tónica — préstamo expresivo y luminoso." },
{ q:"El acorde Eb (Mib mayor) prestado en C mayor tiene la función:", opts:["Dominante","Subdominante","Tónica","Ninguna — está fuera de tonalidad"], a:2, fb:"Eb es el IIIe grado de C menor — función de tónica. En C mayor, reemplaza a Em. Muy utilizado en el rock (I–bIII–IV–I) por su color amplio y masivo." },
{ q:"Para determinar la función de un acorde prestado, se utiliza:", opts:["Su fundamental","El tritono funcional de la tonalidad principal","Su posición en la escala menor","Su número de notas"], a:1, fb:"El tritono funcional (F–B en C mayor/menor) es el referente universal. Si contiene F+B → dominante. F solo → subdominante. Ninguno de los dos → tónica." },
{ q:"La progresión C–Fm–C–G7–C utiliza Fm como:", opts:["Dominante","Sustituto de Em","Subdominante prestada","Acorde de paso"], a:2, fb:"Fm tiene función de subdominante (contiene Fa). Prepara a G7 (dominante) y luego a C (tónica) = SD–D–T. El préstamo colorea la frase sin romper la lógica funcional." },

{ q:"¿Qué principio conecta los acordes en el ciclo de quintas descendentes?", opts:["Cada acorde sube una tercera","Cada acorde desciende una quinta (o sube una cuarta)","Cada acorde está invertido","Cada acorde está en estado fundamental"], a:1, fb:"El ciclo de quintas descendentes: cada fundamental está una quinta por debajo de la anterior. Este movimiento crea una atracción natural — la dinámica más fuerte de la armonía tonal." },
{ q:"¿Qué célebre estándar de jazz está basado en el ciclo de quintas en menor?", opts:["All The Things You Are","Autumn Leaves","Misty","Round Midnight"], a:1, fb:"Autumn Leaves utiliza el ciclo de quintas descendentes en G menor (y Bb mayor) — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. Es el ejemplo pedagógico clásico." },
{ q:"El bajo de chacona desciende típicamente:", opts:["Por quintas","Por grados conjuntos o por terceras desde I hasta V","Por segundas aumentadas","Por octavas"], a:1, fb:"El bajo de chacona crea una línea descendente conjunta o por terceras — Do → Si♭ → La♭ → Sol en C menor. Este bajo es un ostinato sobre el que se desarrollan las variaciones." },
{ q:"En el bajo de chacona, se utiliza excepcionalmente la escala menor:", opts:["Armónica en todos los grados","Natural en el Ve grado (Gm en lugar de G7)","Mayor en el IIIe grado","Dórica en el VIe grado"], a:1, fb:"En el bajo de chacona, se utiliza la menor natural en el Ve grado para fluidificar la línea descendente. La excepción Gm es específica de este contexto." },
{ q:"El acorde napolitano es el grado:", opts:["♭III en primera inversión","♭II en acorde mayor, frecuentemente en primera inversión","IV rebajado","VIIe aumentado"], a:1, fb:"El napolitano = ♭II mayor. En C menor: Db mayor. Generalmente se presenta en 1ª inversión (♭II6) con la tercera en el bajo." },
{ q:"La función armónica del acorde napolitano es:", opts:["Dominante","Tónica","Subdominante","Neutra"], a:2, fb:"El napolitano tiene función de subdominante. En C menor, Db contiene Fa (IVe grado) pero no Si. Prepara la dominante: ♭II6 → V7 → I." },
{ q:"En C menor, el acorde napolitano es:", opts:["Ab mayor","Db mayor / F","Bb mayor","Eb mayor"], a:1, fb:"El ♭II de C es Db (Reb mayor). En primera inversión: Db/F. Es el acorde napolitano de C menor." },
{ q:"¿Qué color expresivo caracteriza al acorde napolitano?", opts:["Alegre y ligero","Dramático y patético","Misterioso y modal","Neutro y estable"], a:1, fb:"El semitono entre el ♭II y la tónica (Reb → Do) está cargado de expresividad dramática. Se encuentra el napolitano en Beethoven, Chopin y en la música de cine para evocar la gravedad o el destino." },
{ q:"El esquema clásico de uso del napolitano es:", opts:["♭II → I → V","♭II6 → V7 → I","I → ♭II → I","V → ♭II → V"], a:1, fb:"♭II6 → V7 → I: el napolitano prepara la dominante como una subdominante reforzada, luego la dominante resuelve sobre la tónica. Esquema muy frecuente en los románticos." },
{ q:"En el ciclo de quintas en C menor, ¿qué acorde sigue a Fm7?", opts:["Cm","Bdim7","G7","EbMaj7"], a:1, fb:"Cm → Fm7 → Bdim7 → EbMaj7... El Bdim7 está una quinta por debajo de Fm (Fa → Si). Es el VIIe grado de C menor armónico." },

{ q:"La progresión Am–F–C–G en A menor toma prestado F de:", opts:["A mayor","C mayor","La menor armónica","F mayor"], a:0, fb:"En A menor, el VIe grado natural es Fa. F es el VIe grado de A menor natural — no es un préstamo aquí. F pertenece diatónicamente a la escala de A menor natural." },
{ q:"La progresión C–Bb–F–C en C mayor toma prestado Bb de:", opts:["G mayor","C menor","F mayor","Bb mayor"], a:2, fb:"Bb (Sib mayor) no pertenece a C mayor. Es el VIIe grado de F mayor, o el VIIe grado de C menor natural. En C mayor, es un préstamo — muy utilizado en el rock (I–bVII–IV–I)." },
{ q:"¿Qué progresión ilustra mejor el préstamo del IV menor en mayor?", opts:["C–F–G7–C","C–Fm–G7–C","C–Dm–G7–C","C–Am–G7–C"], a:1, fb:"C–Fm–G7–C: el Fm está prestado de C menor. Es el préstamo del IVe grado menor en contexto mayor — color oscuro en la subdominante, muy romántico." },
{ q:"En G mayor, el acorde napolitano sería:", opts:["Ab mayor","Ab mayor / C","Eb mayor","F mayor"], a:1, fb:"El ♭II de G es Ab (Lab). En primera inversión con C (Do) en el bajo: Ab/C. Es el napolitano de G mayor." },
{ q:"¿Por qué el ciclo de quintas resulta tan natural al oído?", opts:["Porque evita todas las disonancias","Porque el movimiento de quinta es la consonancia más pura después de la octava","Porque permanece en la misma escala","Porque siempre usa acordes mayores"], a:1, fb:"La quinta justa (relación 3/2) es la consonancia más fundamental después de la octava. Un descenso de quinta crea una atracción acústica natural — por eso este movimiento suena tan inevitable." },
{ q:"Un préstamo es diferente de una modulación porque:", opts:["El préstamo usa acordes invertidos","El préstamo es momentáneo — no se abandona la tonalidad principal","El préstamo siempre va seguido de una cadencia perfecta","El préstamo siempre usa el napolitano"], a:1, fb:"Un préstamo es un color pasajero — un acorde extraño integrado sin desplazar el centro tonal. La modulación instala duraderamente una nueva tonalidad con su propia cadencia." },
{ q:"La progresión C–Ab–Bb–C en C mayor utiliza:", opts:["Dos cadencias perfectas","Dos préstamos de C menor (Ab y Bb)","Una modulación a Ab mayor","Un bajo de chacona"], a:1, fb:"Ab (Lab) y Bb (Sib) están prestados de C menor natural. Esta progresión (I–bVI–bVII–I) es típica del rock — dos préstamos que crean un color modal y masivo." },

{ q:"¿Por qué la escala menor natural proviene del VIe grado de la escala mayor?", opts:["Por convención histórica arbitraria","Porque partiendo del VIe grado se obtiene la misma secuencia T/½ desplazada","Porque es la escala con menos alteraciones","Porque el VIe grado es siempre menor"], a:1, fb:"La escala mayor comienza en el Ie grado. Si se retoma la misma secuencia de tonos/semitonos a partir del VIe, se obtiene la escala menor relativa — mismas notas, punto de partida diferente." },
{ q:"En A menor natural, ¿qué notas son idénticas a C mayor?", opts:["6 notas de 7","7 notas de 7 — exactamente las mismas","5 notas de 7","Ninguna nota en común"], a:1, fb:"Am natural y C mayor comparten exactamente las 7 mismas notas — A B C D E F G. Am es el relativo menor de C mayor." },
{ q:"En C menor armónico, ¿qué nota está alterada respecto a la natural?", opts:["El IVe grado (Fa)","El VIe grado (Lab)","El VIIe grado (Si♭ → Si natural)","El IIe grado (Ré)"], a:2, fb:"La menor armónica eleva el VIIe grado un semitono: Si♭ (Bb) se convierte en Si natural (B). Esto crea la sensible y el tritono funcional." },
{ q:"El intervalo característico de la escala menor armónica es:", opts:["La tercera aumentada entre I y III","El tritono entre IV y VII","El tono y medio entre VI y VII","La segunda disminuida entre V y VI"], a:2, fb:"Entre el VIe (Lab) y el VIIe elevado (Si natural) en C menor armónico, hay 1 tono y medio (3 semitonos). Este intervalo es la firma sonora de la menor armónica — color a veces calificado de oriental." },
{ q:"¿Cuál es el Ve grado en C menor natural?", opts:["Gm","G7","G mayor","Gdim"], a:0, fb:"En C menor natural, el VIIe grado es Bb (no alterado). El acorde construido sobre Sol es G–Bb–D = Gm. Sin la sensible, no hay tensión hacia Cm." },
{ q:"¿Por qué se utiliza la menor natural en el Ie grado en lugar de la armónica?", opts:["Por tradición","Porque la menor armónica crearía Cm con una 7ª mayor (ImMaj7) — acorde inestable","Porque la menor natural es más bella","Porque el Ie grado no necesita tritono"], a:1, fb:"Sobre el Ie grado con menor armónica: C–Eb–G–B = CmMaj7. La 7ª mayor sobre la tónica es muy inestable. Se prefiere la menor natural para mantener Cm o Cm7 como tónica estable." },
{ q:"En D menor armónico, ¿qué nota está elevada?", opts:["Sol (G)","Do (C)","Do# (C#)","Fa# (F#)"], a:2, fb:"D menor natural: D E F G A Bb C. La menor armónica eleva el VIIe grado C → C#. D menor armónico: D E F G A Bb C#." },
{ q:"En E menor armónico, la sensible es:", opts:["Ré (D)","Ré# (D#)","Fa (F)","Sol (G)"], a:1, fb:"E menor natural tiene D como VIIe grado. La menor armónica lo eleva: D → D#. La sensible de E menor armónico es D#." },

{ q:"En G mayor, ¿qué acorde está prestado en la progresión G–Eb–Bb–G?", opts:["Ninguno","Eb y Bb, prestados de G menor","Solo Bb","Solo Eb"], a:1, fb:"En G mayor, Eb (Mib) y Bb (Sib) no pertenecen a la escala. Están prestados de G menor. La progresión G–bVI–bVII–G es típica del rock." },
{ q:"En D mayor, Bb es un préstamo de:", opts:["D menor","G mayor","A mayor","F mayor"], a:0, fb:"En D menor, el VIe grado es Bb (Sib). No es una nota de D mayor — es un préstamo de D menor en contexto de D mayor." },
{ q:"¿Qué préstamo es el más frecuente en la música clásica y romántica?", opts:["El bVII","El bVI","El IV menor (bIV)","El bII"], a:2, fb:"El préstamo del IVe grado menor (IV menor) es de los más frecuentes — F → Fm en C mayor. Aporta un color oscuro y expresivo en la subdominante, muy apreciado por el romanticismo." },
{ q:"En la progresión A–F–C–G, F es:", opts:["Un préstamo de A menor","Diatónico en A mayor","Un acorde de dominante secundaria","Un acorde napolitano"], a:1, fb:"A mayor: A B C# D E F# G#. F natural no pertenece a A mayor. En cambio, F es el VIe grado de A menor — es un préstamo." },
{ q:"El préstamo I menor (ej.: Cm en C mayor) tiene la misma función que:", opts:["Am","F","G7","Em"], a:0, fb:"Cm y Am tienen ambos función de tónica (ninguno contiene F ni B, el tritono de C). Cm puede por tanto reemplazar a Am como tónica alternativa, con un color más oscuro." },
{ q:"En C mayor, ¿cuál es la función de Bb mayor?", opts:["Dominante","Subdominante","Tónica","No tiene una función clara"], a:1, fb:"Bb (Sib mayor) contiene Fa (F) pero no Si (B). Fa solo sin Si = función de subdominante. Bb puede por tanto reemplazar a F o Dm en una progresión SD–D–T." },
{ q:"La progresión C–Cm–C es un ejemplo de:", opts:["Modulación","Péndulo","Minorización momentánea (I → Im)","Cadencia plagal"], a:2, fb:"C → Cm → C: se minoriza momentáneamente la tónica — misma fundamental, pero la tercera pasa de E a Eb. Técnica muy expresiva, utilizada en codas y momentos dramáticos." },
{ q:"En E mayor, el préstamo más frecuente en el rock es:", opts:["Cm","Bm","D (bVII prestado de E menor)","Ab"], a:2, fb:"D mayor (Ré) es el bVII de E mayor — prestado de E menor. La progresión E–D–A–E es clásica del rock (ej.: numerosas canciones de Led Zeppelin, Rolling Stones)." },
{ q:"La progresión I–bVII–IV–I en C mayor es:", opts:["C–Bb–F–C","C–Bb–G–C","C–Ab–F–C","C–Bb–Dm–C"], a:0, fb:"C (I) – Bb (bVII, prestado de C menor) – F (IV) – C (I). Bb es el préstamo del VIIe grado menor. C–Bb–F–C es una progresión icónica del rock." },
{ q:"¿Qué acorde prestado de C menor reemplaza a Em (IIIe grado) en C mayor?", opts:["Cm","Eb","Ab","Fm"], a:1, fb:"Eb (Mib mayor) es el IIIe grado de C menor. Reemplaza a Em con un color más amplio y masivo. La progresión C–Eb–F–G es habitual en el rock y el pop." },
{ q:"¿Por qué se pueden intercambiar acordes entre tonalidades homónimas?", opts:["Porque tienen las mismas notas","Porque comparten el tritono funcional y por tanto las mismas funciones","Porque están en la misma armadura","Porque la melodía permanece idéntica"], a:1, fb:"C mayor y C menor comparten F y B (el tritono funcional). Las funciones se determinan en relación a este tritono — los acordes de ambas tonalidades pueden por tanto intercambiarse libremente." },

{ q:"El ciclo de quintas completo en C mayor es:", opts:["C–F–Bdim–Em–Am–Dm–G7–C","C–G–Dm–Am–Em–Bdim–F–C","C–Dm–Em–F–G–Am–Bdim–C","C–Am–F–Dm–Bdim–G7–Em–C"], a:0, fb:"C → F → Bdim → Em → Am → Dm → G7 → C. Cada acorde está una quinta por debajo del anterior dentro de la escala de C mayor." },
{ q:"En A menor, el ciclo de quintas comienza por:", opts:["Am–Dm–G7–CMaj7–FMaj7–Bm7b5–E7–Am","Am–E7–Dm–G7–CMaj7–Am","Am–Dm–G7–Am","Am–G7–Dm–Am"], a:0, fb:"Am → Dm → G7 → CMaj7 → FMaj7 → Bm7b5 → E7 → Am. Mismo principio que en menor — cada acorde desciende una quinta diatónica." },
{ q:"¿Por qué el ciclo de quintas descendentes es armónicamente tan eficaz?", opts:["Porque evita las disonancias","Porque cada fundamental atrae a la siguiente por el movimiento de quinta — la atracción de bajo más fuerte","Porque permanece en una sola escala","Porque siempre usa acordes mayores"], a:1, fb:"El movimiento de quinta descendente (o cuarta ascendente) en el bajo crea la atracción más natural de la armonía tonal — es la misma lógica que hace que V resuelva hacia I." },
{ q:"En Autumn Leaves, el ciclo de quintas pasa alternativamente de:", opts:["C mayor a G mayor","C menor a Eb mayor","G menor a Bb mayor — relativo menor y mayor","A menor a C mayor"], a:2, fb:"Autumn Leaves está en G menor / Bb mayor (relativos). El ciclo pasa: Cm7–F7–BbMaj7–EbMaj7 (en Bb mayor) luego Am7b5–D7–Gm (en G menor)." },
{ q:"¿Qué acorde completa la secuencia Cm–Fm7–Bdim7–… en el ciclo en C menor?", opts:["G7","AbMaj7","EbMaj7","Dm7b5"], a:2, fb:"Cm → Fm7 → Bdim7 → EbMaj7 → AbMaj7 → Dm7b5 → G7 → Cm. Después de Bdim7, se desciende una quinta: Si → Mi♭ = EbMaj7." },
{ q:"El ciclo de quintas en modo mayor omite frecuentemente los grados IIIe y VIIe porque:", opts:["Son demasiado graves","Son menos utilizados y su función es ambigua","No están en la escala","Crean octavas paralelas"], a:1, fb:"Em (IIIe) y Bdim (VIIe) son armónicamente más complejos y menos frecuentes en las progresiones habituales. En la práctica, el ciclo mayor abreviado suele ser I–IV–V–I." },

{ q:"El bajo de chacona se utiliza principalmente como:", opts:["Una progresión de 8 acordes","Un ostinato que sirve de base para las variaciones","Una serie de cadencias perfectas","Un ciclo de quintas en menor"], a:1, fb:"El bajo de chacona es un ostinato — una figura de bajo repetida indefinidamente sobre la que el compositor construye variaciones melódicas, rítmicas y armónicas." },
{ q:"¿Qué gran compositor barroco escribió una de las chaconas más célebres para violín solo?", opts:["Vivaldi","Handel","Purcell","Bach"], a:3, fb:"La Chacona de la Partita n°2 en Re menor de J.S. Bach es una de las obras más monumentales para violín solo — una serie de variaciones sobre un bajo de chacona." },
{ q:"El bajo de chacona crea una tensión progresiva porque:", opts:["Sube hacia el agudo","Desciende hacia la dominante, creando una expectativa de resolución","Se mantiene en la tónica","Utiliza acordes disminuidos"], a:1, fb:"El bajo desciende por grados (Do → Si♭ → La♭ → Sol en C menor) y llega a Sol (dominante), que reclama la resolución hacia Cm. Es una tensión construida por el movimiento melódico del bajo." },
{ q:"¿Qué acorde del bajo de chacona utiliza excepcionalmente la menor natural?", opts:["El Ie grado","El IVe grado","El Ve grado (Gm en lugar de G7)","El VIe grado"], a:2, fb:"En el bajo de chacona, el Ve grado utiliza la menor natural (Gm) para fluidificar la línea de bajo descendente. El G7 armónico sería más tenso pero menos natural en este contexto melódico." },
{ q:"La progresión Cm–Gm/Bb–Fm/Ab–G7 es un bajo de chacona. El bajo toca:", opts:["Do–Sol–Fa–Sol","Do–Si♭–La♭–Sol","Do–Mi♭–Sol–Si","Do–Ré–Mi–Fa"], a:1, fb:"El bajo toca: Do (C) sobre Cm → Si♭ (Bb) sobre Gm/Bb → La♭ (Ab) sobre Fm/Ab → Sol (G) sobre G7. Línea descendente conjunta característica." },
{ q:"¿Qué elemento musical moderno proviene directamente de la tradición de la chacona?", opts:["El chorus en el jazz","El bajo ostinato en el blues y el funk","La modulación por pivote","El acorde napolitano en el pop"], a:1, fb:"El bajo ostinato del blues (12-bar blues) y del funk son descendientes directos de la chacona barroca — un bajo repetido sobre el que se desarrollan las variaciones melódicas y rítmicas." },

{ q:"En G menor, el acorde napolitano es:", opts:["Eb/G","Ab/C","Ab mayor","Db mayor"], a:1, fb:"El ♭II de G es Ab (Lab mayor). En primera inversión con C en el bajo: Ab/C. Es el acorde napolitano de G menor." },
{ q:"En D menor, el acorde napolitano es:", opts:["Eb mayor","Eb/G","Bb mayor","Gb mayor"], a:1, fb:"El ♭II de D es Eb (Mib mayor). En primera inversión con G en el bajo: Eb/G. El acorde napolitano de D menor es Eb/G." },
{ q:"El napolitano se presenta generalmente en primera inversión porque:", opts:["Es más fácil de tocar","La tercera en el bajo crea un movimiento conjunto más fluido hacia la dominante","Suena más fuerte","Por convención histórica sin razón acústica"], a:1, fb:"En primera inversión (♭II6), el bajo es la tercera del ♭II. Esta voz desciende un semitono hacia la sensible de la dominante — movimiento conjunto muy expresivo y natural." },
{ q:"El semitono entre el ♭II y la tónica crea tensión porque:", opts:["Es un intervalo raro","La proximidad engendra una fuerte atracción — como la sensible hacia la tónica","El ♭II es siempre inestable","Las dos notas están a 7 semitonos de distancia"], a:1, fb:"Reb → Do (Db → C) es un movimiento de semitono descendente cargado de expresividad. Como la sensible (B → C), esta proximidad crea una atracción intensa — es la esencia del pathos romántico." },
{ q:"Beethoven utiliza el napolitano en:", opts:["La Sonata Claro de Luna (op.27)","La 9ª Sinfonía","Ambas"], a:0, fb:"La Sonata Claro de Luna (op.27 n°2) utiliza el acorde napolitano de forma característica. Beethoven recurre frecuentemente a él para acentuar el carácter dramático." },
];

const questionsDe: Question[] = [{ q:"Warum ist die natürliche Molltonleiter harmonisch problematisch?", opts:["Sie hat zu viele Noten","Ihr Tritonus drängt nicht zur Tonika hin","Sie hat keinen VII. Grad","Sie enthält zu viele Vorzeichen"], a:1, fb:"In der natürlichen Molltonleiter liegt der Tritonus zwischen dem II. und VI. Grad — er löst sich nicht zum I. und III. Grad auf wie in Dur. Keine funktionale Leittonwirkung." },
{ q:"Wie löst die harmonische Molltonleiter dieses Problem?", opts:["Indem sie den Tritonus entfernt","Indem sie den VII. Grad um einen Halbton erhöht","Indem sie den IV. Grad erniedrigt","Indem sie eine 8. Note hinzufügt"], a:1, fb:"Die Erhöhung des VII. Grades erzeugt einen starken Leitton (B statt Bb in C-Moll) und stellt einen funktionalen Tritonus zwischen dem IV. und VII. Grad wieder her — wie in Dur." },
{ q:"Was bringt die harmonische Molltonleiter, was die natürliche nicht hat?", opts:["Eine zusätzliche Oktave","Einen Leitton und einen funktionalen Tritonus","Drei neue Noten","Einen Molldominantakkord"], a:1, fb:"Die harmonische Molltonleiter stellt den Leitton (VII → I, aufsteigender Halbton) und den funktionalen Tritonus (IV + VII) wieder her. Ohne das wäre der Dominantakkord ein Mollakkord (Gm statt G7)." },
{ q:"Welcher Akkord bildet in C harmonisch Moll die Dominante?", opts:["Gm","G","G7","Dm"], a:2, fb:"Mit dem erhöhten VII. Grad (B naturel) ist der auf G aufgebaute Akkord G–B–D–F = G7. Die kleine Septime (F) stammt aus der Tonleiter, das B naturel aus der harmonischen Molltonleiter." },
{ q:"Auf welchen Graden verwendet man lieber natürliches Moll als harmonisches?", opts:["IV. und V.","I. und III.","II. und VII.","V. und VI."], a:1, fb:"Der I. Grad (Tonika) und der III. Grad (parallele Durtonart) verwenden natürliches Moll, um stabil zu bleiben. Harmonisches Moll auf diesen Graden würde zu instabile Intervalle erzeugen (große Septime, übermäßige Quinte)." },
{ q:"Was ist in C-Moll der Unterschied zwischen Gm (natürlich) und G7 (harmonisch)?", opts:["Der Grundton","Die Terz","Die Septime und die Terz — B♭ vs. B naturel","Die Quinte"], a:2, fb:"In natürlichem Moll: G–Bb–D = Gm. In harmonischem Moll: G–B–D–F = G7. Die Terz wechselt von Bb zu B naturel, was den Leitton erzeugt und die Auflösung nach Cm ermöglicht." },
{ q:"Die Formel der harmonischen Molltonleiter lautet:", opts:["G–G–½–G–G–G–½","G–½–G–G–½–G–G","G–½–G–G–½–1½–½","½–G–G–G–½–G–G"], a:2, fb:"G–½–G–G–½–1½–½: der Anderthalbton (1½) zwischen dem VI. und VII. Grad ist charakteristisch für die harmonische Molltonleiter — ein großer melodischer Sprung, der ihr ihren orientalischen Klang verleiht." },
{ q:"Was ist eine harmonische Ausleihe (Emprunt)?", opts:["Ein zweimal gespielter Akkord","Ein Akkord aus einer anderen Tonart, der vorübergehend verwendet wird","Eine ungewöhnliche Umkehrung","Eine dauerhafte Modulation"], a:1, fb:"Eine Ausleihe bedeutet, vorübergehend einen Akkord aus einer anderen Tonart zu verwenden — ohne die Haupttonart zu verlassen. Die Funktion bleibt dank des funktionalen Tritonus erkennbar." },
{ q:"Warum teilen C-Dur und C-Moll denselben funktionalen Tritonus?", opts:["Durch Zufall","Weil sie dieselbe Tonika haben und der Tritonus F–B beiden Tonleitern gemeinsam ist","Weil sie dieselben Noten haben","Weil der Leitton identisch ist"], a:1, fb:"F und B sind in beiden Tonarten vorhanden — dieser Tritonus bestimmt die harmonischen Funktionen. Deshalb können Akkorde beider Tonarten ausgetauscht werden, ohne die funktionale Logik zu brechen." },
{ q:"Welcher Akkord aus C-Moll kann F (IV. Grad) in C-Dur ersetzen?", opts:["Cm","Fm","Ab","Eb"], a:1, fb:"Fm ist die Subdominante von C-Moll. Wie F hat es die Subdominantfunktion (enthält F, aber nicht B). Fm kann daher F in C-Dur ersetzen — eine sehr ausdrucksstarke Ausleihe." },
{ q:"Die Progression C–Fm–C ist ein Beispiel für:", opts:["Eine Modulation nach C-Moll","Eine Ausleihe des IV. Mollgrades","Eine Trugkadenz","Den Quintenzirkel"], a:1, fb:"C (Tonika) → Fm (aus C-Moll ausgeliehene Subdominante) → C (Tonika). Das Fm ist eine Ausleihe — man bleibt in C-Dur, färbt die Phrase aber mit einem Mollton." },
{ q:"Welche Funktion hat Ab in C-Dur?", opts:["Dominante","Subdominante","Tonika (ausgeliehen aus C-Moll)","Modulierend"], a:2, fb:"Ab ist der VI. Grad von C-Moll. Er hat Tonikafunktion (enthält weder F noch B). In C-Dur ersetzt er Am als Tonikaersatz — eine ausdrucksstarke und leuchtende Ausleihe." },
{ q:"Der aus C-Dur ausgeliehene Akkord Eb hat die Funktion:", opts:["Dominante","Subdominante","Tonika","Keine — er liegt außerhalb der Tonart"], a:2, fb:"Eb ist der III. Grad von C-Moll — Tonikafunktion. In C-Dur ersetzt er Em. Im Rock sehr verbreitet (I–bIII–IV–I) wegen seiner breiten und massiven Klangfarbe." },
{ q:"Um die Funktion eines ausgeliehenen Akkords zu bestimmen, verwendet man:", opts:["Seinen Grundton","Den funktionalen Tritonus der Haupttonart","Seine Position in der Molltonleiter","Seine Notenanzahl"], a:1, fb:"Der funktionale Tritonus (F–B in C-Dur/Moll) ist der universelle Orientierungspunkt. Enthält er F+B → Dominante. Nur F → Subdominante. Keines von beiden → Tonika." },
{ q:"Die Progression C–Fm–C–G7–C verwendet Fm als:", opts:["Dominante","Ersatz für Em","Ausgeliehene Subdominante","Durchgangsakkord"], a:2, fb:"Fm hat die Subdominantfunktion (enthält F). Es bereitet G7 (Dominante) dann C (Tonika) vor = SD–D–T. Die Ausleihe färbt die Phrase, ohne die funktionale Logik zu brechen." },
{ q:"Welches Prinzip verbindet die Akkorde im absteigenden Quintenzirkel?", opts:["Jeder Akkord steigt um eine Terz","Jeder Akkord fällt um eine Quinte (oder steigt um eine Quarte)","Jeder Akkord wird umgekehrt","Jeder Akkord steht in Grundstellung"], a:1, fb:"Im absteigenden Quintenzirkel liegt jeder Grundton eine Quinte unter dem vorherigen. Diese Bewegung erzeugt eine natürliche Anziehung — die stärkste Dynamik der tonalen Harmonik." },
{ q:"Welcher berühmte Jazzstandard basiert auf dem Quintenzirkel in Moll?", opts:["All The Things You Are","Autumn Leaves","Misty","Round Midnight"], a:1, fb:"Autumn Leaves verwendet den absteigenden Quintenzirkel in G-Moll (und Bb-Dur) — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. Es ist das klassische pädagogische Beispiel." },
{ q:"Die Chaconne-Basslinie steigt typischerweise:", opts:["In Quinten","Stufenweise oder in Terzen von I nach V abwärts","In übermäßigen Sekunden","In Oktaven"], a:1, fb:"Die Chaconne-Basslinie erzeugt eine absteigende Stufenweise- oder Terzbewegung — Do → Si♭ → La♭ → Sol in C-Moll. Diese Basslinie ist ein Ostinato, über dem Variationen entwickelt werden." },
{ q:"In der Chaconne-Basslinie verwendet man ausnahmsweise die Molltonleiter:", opts:["Harmonisch auf allen Graden","Natürlich auf dem V. Grad (Gm statt G7)","Dur auf dem III. Grad","Dorisch auf dem VI. Grad"], a:1, fb:"In der Chaconne-Basslinie verwendet man auf dem V. Grad natürliches Moll (Gm), um die absteigende Linie zu glätten. Die Ausnahme Gm ist spezifisch für diesen Kontext." },
{ q:"Der neapolitanische Akkord ist der Grad:", opts:["♭III in erster Umkehrung","♭II als Durakkord, oft in erster Umkehrung","Erniedrigter IV.","Übermäßiger VII."], a:1, fb:"Der Neapolitaner = ♭II Dur. In C-Moll: Db-Dur. Er wird in der Regel in erster Umkehrung präsentiert (♭II6) mit der Terz im Bass." },
{ q:"Die harmonische Funktion des neapolitanischen Akkords ist:", opts:["Dominante","Tonika","Subdominante","Neutral"], a:2, fb:"Der Neapolitaner hat Subdominantfunktion. In C-Moll enthält Db F (IV. Grad) aber nicht B. Er bereitet die Dominante vor: ♭II6 → V7 → I." },
{ q:"In C-Moll ist der neapolitanische Akkord:", opts:["Ab-Dur","Db-Dur / F","Bb-Dur","Eb-Dur"], a:1, fb:"Das ♭II von C ist Db (Db-Dur). In erster Umkehrung: Db/F. Das ist der neapolitanische Akkord von C-Moll." },
{ q:"Welcher expressive Charakter kennzeichnet den neapolitanischen Akkord?", opts:["Heiter und leicht","Dramatisch und pathetisch","Geheimnisvoll und modal","Neutral und stabil"], a:1, fb:"Der Halbton zwischen ♭II und Tonika (Db → C) ist ausdrucksstark dramatisch. Den Neapolitaner findet man bei Beethoven, Chopin und in Filmmusik, um Schwere oder Schicksal zu evozieren." },
{ q:"Das klassische Schema für die Verwendung des Neapolitaners ist:", opts:["♭II → I → V","♭II6 → V7 → I","I → ♭II → I","V → ♭II → V"], a:1, fb:"♭II6 → V7 → I: Der Neapolitaner bereitet die Dominante als verstärkte Subdominante vor, dann löst die Dominante zur Tonika auf. Sehr häufiges Schema bei den Romantikern." },
{ q:"Welcher Akkord folgt in der Quintenkreisfolge in C-Moll auf Fm7?", opts:["Cm","Bdim7","G7","EbMaj7"], a:1, fb:"Cm → Fm7 → Bdim7 → EbMaj7... Das Bdim7 liegt eine Quinte unter Fm (Fa → Si). Es ist der VII. Grad von C harmonisch Moll." },
{ q:"Die Progression Am–F–C–G in A-Moll leiht F aus:", opts:["A-Dur","C-Dur","Harmonischem Moll","F-Dur"], a:0, fb:"In A-Moll ist der natürliche VI. Grad Fa. F ist der VI. Grad von A natürlichem Moll — hier keine Ausleihe. F gehört diatonisch zur A-natürlichen Molltonleiter." },
{ q:"Die Progression C–Bb–F–C in C-Dur leiht Bb aus:", opts:["G-Dur","C-Moll","F-Dur","Bb-Dur"], a:2, fb:"Bb gehört nicht zu C-Dur. Es ist der VII. Grad von F-Dur oder der VII. Grad von natürlichem C-Moll. In C-Dur ist es eine Ausleihe — oft im Rock verwendet (I–bVII–IV–I)." },
{ q:"Welche Progression veranschaulicht am besten die Ausleihe des IV. Mollgrades in Dur?", opts:["C–F–G7–C","C–Fm–G7–C","C–Dm–G7–C","C–Am–G7–C"], a:1, fb:"C–Fm–G7–C: das Fm ist aus C-Moll ausgeliehen. Das ist die Ausleihe des IV. Mollgrades im Durkontext — dunkle Farbe auf der Subdominante, sehr romantisch." },
{ q:"In G-Dur wäre der neapolitanische Akkord:", opts:["Ab-Dur","Ab-Dur / C","Eb-Dur","F-Dur"], a:1, fb:"Das ♭II von G ist Ab. In erster Umkehrung mit C im Bass: Ab/C. Das ist der Neapolitaner von G-Dur." },
{ q:"Warum klingt der Quintenzirkel so natürlich für das Ohr?", opts:["Weil er alle Dissonanzen vermeidet","Weil die Quintbewegung die reinste Konsonanz nach der Oktave ist","Weil er in derselben Tonleiter bleibt","Weil er immer Durakkorde verwendet"], a:1, fb:"Die reine Quinte (Verhältnis 3/2) ist die grundlegendste Konsonanz nach der Oktave. Ein Quintabfall erzeugt eine natürliche akustische Anziehung — deshalb klingt diese Bewegung so unvermeidlich." },
{ q:"Eine Ausleihe unterscheidet sich von einer Modulation, weil:", opts:["Die Ausleihe umgekehrte Akkorde verwendet","Die Ausleihe vorübergehend ist — man verlässt die Haupttonart nicht","Auf eine Ausleihe immer eine vollkommene Kadenz folgt","Die Ausleihe immer den Neapolitaner verwendet"], a:1, fb:"Eine Ausleihe ist eine flüchtige Farbe — ein fremder Akkord, der integriert wird, ohne das tonale Zentrum zu verschieben. Eine Modulation etabliert dauerhaft eine neue Tonart mit eigener Kadenz." },
{ q:"Die Progression C–Ab–Bb–C in C-Dur verwendet:", opts:["Zwei vollkommene Kadenzen","Zwei Ausleihen aus C-Moll (Ab und Bb)","Eine Modulation nach Ab-Dur","Eine Chaconne-Basslinie"], a:1, fb:"Ab und Bb sind aus natürlichem C-Moll ausgeliehen. Diese Progression (I–bVI–bVII–I) ist typisch für Rock — zwei Ausleihen, die eine modale und massive Klangfarbe erzeugen." },
{ q:"Warum stammt die natürliche Molltonleiter vom VI. Grad der Durtonleiter?", opts:["Aus willkürlicher historischer Konvention","Weil man beim VI. Grad beginnend dieselbe T/½-Folge verschoben erhält","Weil es die Tonleiter mit den wenigsten Vorzeichen ist","Weil der VI. Grad immer Moll ist"], a:1, fb:"Die Durtonleiter beginnt auf dem I. Grad. Nimmt man dieselbe Ganz-/Halbtonfolge ab dem VI. Grad, erhält man die relative Molltonleiter — dieselben Noten, anderer Ausgangspunkt." },
{ q:"Welche Noten in A natürlichem Moll sind identisch mit C-Dur?", opts:["6 von 7 Noten","7 von 7 Noten — exakt dieselben","5 von 7 Noten","Keine gemeinsamen Noten"], a:1, fb:"Am natürlich und C-Dur teilen genau dieselben 7 Noten — A B C D E F G. Am ist die Paralleltonart (relatives Moll) von C-Dur." },
{ q:"Welche Note ist in C harmonisch Moll gegenüber dem natürlichen Moll alteriert?", opts:["Der IV. Grad (F)","Der VI. Grad (Ab)","Der VII. Grad (B♭ → B naturel)","Der II. Grad (D)"], a:2, fb:"Die harmonische Molltonleiter erhöht den VII. Grad um einen Halbton: Bb wird zu B naturel. Das erzeugt den Leitton und den funktionalen Tritonus." },
{ q:"Das charakteristische Intervall der harmonischen Molltonleiter ist:", opts:["Die übermäßige Terz zwischen I und III","Der Tritonus zwischen IV und VII","Der Anderthalbton zwischen VI und VII","Die verminderte Sekunde zwischen V und VI"], a:2, fb:"Zwischen dem VI. Grad (Ab) und dem erhöhten VII. Grad (B naturel) in C harmonisch Moll liegen 1½ Töne (3 Halbtöne). Dieses Intervall ist das Klangmerkmal der harmonischen Molltonleiter — manchmal als orientalisch bezeichnet." },
{ q:"Was ist der V. Grad in C natürlichem Moll?", opts:["Gm","G7","G-Dur","Gdim"], a:0, fb:"In C natürlichem Moll ist der VII. Grad Bb (nicht alteriert). Der auf G aufgebaute Akkord ist G–Bb–D = Gm. Ohne den Leitton gibt es keine Spannung zu Cm hin." },
{ q:"Warum verwendet man auf dem I. Grad lieber natürliches als harmonisches Moll?", opts:["Aus Tradition","Weil harmonisches Moll Cm mit einer großen Septime (ImMaj7) erzeugen würde — ein instabiler Akkord","Weil natürliches Moll schöner klingt","Weil der I. Grad keinen Tritonus braucht"], a:1, fb:"Auf dem I. Grad mit harmonischem Moll: C–Eb–G–B = CmMaj7. Die große Septime auf der Tonika ist sehr instabil. Man bevorzugt natürliches Moll, um Cm oder Cm7 als stabile Tonika zu behalten." },
{ q:"In D harmonisch Moll wird welche Note erhöht?", opts:["G","C","C# (C#)","F# (F#)"], a:2, fb:"D natürliches Moll: D E F G A Bb C. Die harmonische Molltonleiter erhöht den VII. Grad C → C#. D harmonisch Moll: D E F G A Bb C#." },
{ q:"In E harmonisch Moll ist der Leitton:", opts:["D","D#","F","G"], a:1, fb:"E natürliches Moll hat D als VII. Grad. Die harmonische Molltonleiter erhöht ihn: D → D#. Der Leitton von E harmonisch Moll ist D#." },
{ q:"In G-Dur, welcher Akkord ist in der Progression G–Eb–Bb–G ausgeliehen?", opts:["Keiner","Eb und Bb, ausgeliehen aus G-Moll","Nur Bb","Nur Eb"], a:1, fb:"In G-Dur gehören Eb und Bb nicht zur Tonleiter. Sie sind aus G-Moll ausgeliehen. Die Progression G–bVI–bVII–G ist typisch für Rock." },
{ q:"In D-Dur ist Bb eine Ausleihe aus:", opts:["D-Moll","G-Dur","A-Dur","F-Dur"], a:0, fb:"In D-Moll ist der VI. Grad Bb. Das ist keine Note von D-Dur — in einem D-Dur-Kontext ist es eine Ausleihe aus D-Moll." },
{ q:"Welche Ausleihe ist in der Klassik und Romantik am häufigsten?", opts:["Das bVII","Das bVI","Der IV. Mollgrad (bIV)","Das bII"], a:2, fb:"Die Ausleihe des IV. Mollgrades ist eine der häufigsten — F → Fm in C-Dur. Sie bringt eine dunkle, ausdrucksstarke Farbe auf der Subdominante, die die Romantik sehr schätzte." },
{ q:"In der Progression A–F–C–G ist F:", opts:["Eine Ausleihe aus A-Moll","Diatonisch zu A-Dur","Ein sekundärer Dominantakkord","Ein neapolitanischer Akkord"], a:1, fb:"A-Dur: A B C# D E F# G#. F naturel gehört nicht zu A-Dur. Hingegen ist F der VI. Grad von A-Moll — es ist eine Ausleihe." },
{ q:"Die Ausleihe I Moll (z. B. Cm in C-Dur) hat dieselbe Funktion wie:", opts:["Am","F","G7","Em"], a:0, fb:"Cm und Am haben beide Tonikafunktion (keines enthält F oder B, den Tritonus von C). Cm kann daher Am als alternative Tonika ersetzen, mit dunklerer Klangfarbe." },
{ q:"Was ist in C-Dur die Funktion von Bb-Dur?", opts:["Dominante","Subdominante","Tonika","Es hat keine klare Funktion"], a:1, fb:"Bb enthält F, aber nicht B. F allein ohne B = Subdominantfunktion. Bb kann daher F oder Dm in einer SD–D–T-Progression ersetzen." },
{ q:"Die Progression C–Cm–C ist ein Beispiel für:", opts:["Modulation","Pendelakkord","Momentane Minorisierung (I → Im)","Plagalkadenz"], a:2, fb:"C → Cm → C: die Tonika wird momentan minorisiert — gleicher Grundton, aber die Terz wechselt von E zu Eb. Sehr ausdrucksstarke Technik, verwendet in Codas und dramatischen Momenten." },
{ q:"In E-Dur ist die häufigste Rock-Ausleihe:", opts:["Cm","Bm","D (bVII, ausgeliehen aus E-Moll)","Ab"], a:2, fb:"D-Dur ist das bVII von E-Dur — aus E-Moll ausgeliehen. Die Progression E–D–A–E ist ein Rock-Klassiker (z. B. zahlreiche Stücke von Led Zeppelin, Rolling Stones)." },
{ q:"Die Progression I–bVII–IV–I in C-Dur lautet:", opts:["C–Bb–F–C","C–Bb–G–C","C–Ab–F–C","C–Bb–Dm–C"], a:0, fb:"C (I) – Bb (bVII, aus C-Moll ausgeliehen) – F (IV) – C (I). Bb ist die Ausleihe des VII. Mollgrades. C–Bb–F–C ist eine ikonische Rock-Progression." },
{ q:"Welcher aus C-Moll ausgeliehene Akkord ersetzt Em (III. Grad) in C-Dur?", opts:["Cm","Eb","Ab","Fm"], a:1, fb:"Eb ist der III. Grad von C-Moll. Er ersetzt Em mit einer breiteren und massiveren Klangfarbe. Die Progression C–Eb–F–G ist in Rock und Pop verbreitet." },
{ q:"Warum kann man Akkorde zwischen gleichnamigen Tonarten austauschen?", opts:["Weil sie dieselben Noten haben","Weil sie den funktionalen Tritonus teilen und daher dieselben Funktionen haben","Weil sie in derselben Tonart stehen","Weil die Melodie identisch bleibt"], a:1, fb:"C-Dur und C-Moll teilen F und B (den funktionalen Tritonus). Die Funktionen werden in Bezug auf diesen Tritonus bestimmt — die Akkorde beider Tonarten können daher frei ausgetauscht werden." },
{ q:"Der vollständige Quintenzirkel in C-Dur lautet:", opts:["C–F–Bdim–Em–Am–Dm–G7–C","C–G–Dm–Am–Em–Bdim–F–C","C–Dm–Em–F–G–Am–Bdim–C","C–Am–F–Dm–Bdim–G7–Em–C"], a:0, fb:"C → F → Bdim → Em → Am → Dm → G7 → C. Jeder Akkord liegt eine Quinte unter dem vorherigen in der C-Dur-Tonleiter." },
{ q:"In A-Moll beginnt der Quintenzirkel mit:", opts:["Am–Dm–G7–CMaj7–FMaj7–Bm7b5–E7–Am","Am–E7–Dm–G7–CMaj7–Am","Am–Dm–G7–Am","Am–G7–Dm–Am"], a:0, fb:"Am → Dm → G7 → CMaj7 → FMaj7 → Bm7b5 → E7 → Am. Dasselbe Prinzip wie in Moll — jeder Akkord fällt um eine diatonische Quinte." },
{ q:"Warum ist der absteigende Quintenzirkel harmonisch so effektiv?", opts:["Weil er Dissonanzen vermeidet","Weil jeder Grundton den nächsten durch die Quintbewegung anzieht — die stärkste Bassanziehung","Weil er in einer einzigen Tonleiter bleibt","Weil er immer Durakkorde verwendet"], a:1, fb:"Die absteigende Quintbewegung (oder aufsteigende Quarte) im Bass erzeugt die natürlichste Anziehung der tonalen Harmonik — dieselbe Logik, die V zu I auflösen lässt." },
{ q:"In Autumn Leaves wechselt der Quintenzirkel abwechselnd von:", opts:["C-Dur nach G-Dur","C-Moll nach Eb-Dur","G-Moll nach Bb-Dur — Parallelmoll und Paralleldur","A-Moll nach C-Dur"], a:2, fb:"Autumn Leaves steht in G-Moll / Bb-Dur (Paralleltonarten). Der Zirkel geht: Cm7–F7–BbMaj7–EbMaj7 (in Bb-Dur), dann Am7b5–D7–Gm (in G-Moll)." },
{ q:"Welcher Akkord vervollständigt die Folge Cm–Fm7–Bdim7–… im Quintenzirkel in C-Moll?", opts:["G7","AbMaj7","EbMaj7","Dm7b5"], a:2, fb:"Cm → Fm7 → Bdim7 → EbMaj7 → AbMaj7 → Dm7b5 → G7 → Cm. Nach Bdim7 fällt man eine Quinte: Si → Mi♭ = EbMaj7." },
{ q:"Der Quintenzirkel in Dur lässt oft den III. und VII. Grad aus, weil:", opts:["Sie zu tief sind","Sie weniger verwendet werden und ihre Funktion mehrdeutig ist","Sie nicht in der Tonleiter sind","Sie Parallelquinten erzeugen"], a:1, fb:"Em (III.) und Bdim (VII.) sind harmonisch komplexer und in gängigen Progressionen seltener. In der Praxis ist der verkürzte Durquintenzirkel oft I–IV–V–I." },
{ q:"Die Chaconne-Basslinie wird hauptsächlich verwendet als:", opts:["Eine Progression aus 8 Akkorden","Ein Ostinato als Grundlage für Variationen","Eine Folge vollkommener Kadenzen","Ein Quintenzirkel in Moll"], a:1, fb:"Die Chaconne-Basslinie ist ein Ostinato — eine unendlich wiederholte Bassfigur, über der der Komponist melodische, rhythmische und harmonische Variationen aufbaut." },
{ q:"Welcher große Barockkomponist schrieb eine der berühmtesten Chaconnen für Solovioline?", opts:["Vivaldi","Handel","Purcell","Bach"], a:3, fb:"Die Chaconne aus der Partita Nr. 2 in d-Moll von J.S. Bach ist eines der monumentalsten Werke für Solovioline — eine Variationsreihe über eine Chaconne-Basslinie." },
{ q:"Die Chaconne-Basslinie erzeugt eine progressive Spannung, weil:", opts:["Sie in die Höhe steigt","Sie zur Dominante hinabsteigt und eine Auflösungserwartung erzeugt","Sie auf der Tonika verweilt","Sie verminderte Akkorde verwendet"], a:1, fb:"Die Basslinie steigt stufenweise ab (Do → Si♭ → La♭ → Sol in C-Moll) und erreicht Sol (Dominante), das die Auflösung zu Do fordert. Diese Anziehungskraft der Dominante ist der Motor der Progression." },
];

const questionsIt: Question[] = [{ q:"Perché la scala minore naturale pone un problema armonico?", opts:["Ha troppe note","Il suo tritono non spinge verso la tonica","Non ha il VII grado","Contiene troppe alterazioni"], a:1, fb:"In minore naturale, il tritono si trova tra il II e il VI grado — non risolve verso il I e il III grado come in maggiore. Nessuna sensibile funzionale." },
{ q:"Come la scala minore armonica risolve questo problema?", opts:["Eliminando il tritono","Alzando il VII grado di un semitono","Abbassando il IV grado","Aggiungendo un'8a nota"], a:1, fb:"Alzare il VII grado crea una sensibile forte (B naturale invece di Bb in C minore) e ristabilisce un tritono funzionale tra il IV e il VII grado — come in maggiore." },
{ q:"Cosa apporta la scala minore armonica che la naturale non ha?", opts:["Un'ottava supplementare","Una sensibile e un tritono funzionale","Tre nuove note","Un accordo di dominante minore"], a:1, fb:"La minore armonica ricrea la sensibile (VII → I, semitono ascendente) e il tritono funzionale (IV + VII). Senza di esso, l'accordo di dominante sarebbe minore (Gm invece di G7)." },
{ q:"In C minore armonico, quale accordo forma la dominante?", opts:["Gm","G","G7","Dm"], a:2, fb:"Con il VII grado alzato (B naturale), l'accordo costruito su Sol è G–B–D–F = G7. La settima minore (F) proviene dalla scala, il B naturale viene dalla minore armonica." },
{ q:"Su quali gradi si usa la minore naturale piuttosto che l'armonica?", opts:["IV e V","I e III","II e VII","V e VI"], a:1, fb:"Il I (tonica) e il III (relativo maggiore) grado usano la minore naturale per restare stabili. La minore armonica su questi gradi creerebbe intervalli troppo instabili (7a maggiore, 5a aumentata)." },
{ q:"In C minore, qual è la differenza tra Gm (naturale) e G7 (armonico)?", opts:["La fondamentale","La terza","La settima e la terza — B♭ vs B naturale","La quinta"], a:2, fb:"In minore naturale: G–Bb–D = Gm. In minore armonica: G–B–D–F = G7. La terza passa da Bb a B naturale, il che crea la sensibile e permette la risoluzione su Cm." },
{ q:"La formula della scala minore armonica è:", opts:["T–T–½–T–T–T–½","T–½–T–T–½–T–T","T–½–T–T–½–1½–½","½–T–T–T–½–T–T"], a:2, fb:"T–½–T–T–½–1½–½: il tono e mezzo tra il VI e il VII grado è caratteristico della minore armonica — un grande salto melodico che le conferisce il suo colore orientale." },

{ q:"Cos'è un prestito armonico?", opts:["Un accordo suonato due volte","Un accordo proveniente da una tonalità diversa, usato temporaneamente","Un rivolto insolito","Una modulazione permanente"], a:1, fb:"Un prestito consiste nell'utilizzare momentaneamente un accordo di un'altra tonalità — senza abbandonare la tonalità principale. La funzione rimane identificabile grazie al tritono funzionale." },
{ q:"Perché C maggiore e C minore condividono lo stesso tritono funzionale?", opts:["Per caso","Perché hanno la stessa tonica e il tritono F–B è comune a entrambe le scale","Perché hanno le stesse note","Perché la sensibile è identica"], a:1, fb:"F e B (Fa e Si) sono presenti in entrambe le tonalità — questo tritono determina le funzioni armoniche. Ecco perché gli accordi delle due tonalità possono essere scambiati senza rompere la logica funzionale." },
{ q:"Quale accordo di C minore può sostituire F (IV grado) in C maggiore?", opts:["Cm","Fm","Ab","Eb"], a:1, fb:"Fm è la sottodominante di C minore. Come F, ha la funzione di sottodominante (contiene Fa ma non Si). Fm può quindi sostituire F in C maggiore — prestito molto espressivo." },
{ q:"La progressione C–Fm–C è un esempio di:", opts:["Modulazione in C minore","Prestito del IV grado minore","Cadenza d'inganno","Ciclo delle quinte"], a:1, fb:"C (tonica) → Fm (sottodominante presa in prestito da C minore) → C (tonica). Il Fm è un prestito — si resta in C maggiore ma si colora la frase con una sfumatura minore." },
{ q:"Qual è la funzione di Ab (Lab maggiore) in C maggiore?", opts:["Dominante","Sottodominante","Tonica (preso in prestito da C minore)","Modulante"], a:2, fb:"Ab è il VI grado di C minore. Ha la funzione di tonica (non contiene né Fa né Si). In C maggiore, sostituisce Am come sostituto della tonica — prestito espressivo e luminoso." },
{ q:"L'accordo Eb (Mib maggiore) preso in prestito in C maggiore ha la funzione di:", opts:["Dominante","Sottodominante","Tonica","Nessuna — è fuori tonalità"], a:2, fb:"Eb è il III grado di C minore — funzione tonica. In C maggiore, sostituisce Em. Molto usato nel rock (I–bIII–IV–I) per il suo colore ampio e massiccio." },
{ q:"Per determinare la funzione di un accordo preso in prestito, si usa:", opts:["La sua fondamentale","Il tritono funzionale della tonalità principale","La sua posizione nella scala minore","Il suo numero di note"], a:1, fb:"Il tritono funzionale (F–B in C maggiore/minore) è il riferimento universale. Se contiene F+B → dominante. Solo F → sottodominante. Né l'uno né l'altro → tonica." },
{ q:"La progressione C–Fm–C–G7–C usa Fm come:", opts:["Dominante","Sostituto di Em","Sottodominante presa in prestito","Accordo di passaggio"], a:2, fb:"Fm ha la funzione di sottodominante (contiene Fa). Prepara G7 (dominante) poi C (tonica) = SD–D–T. Il prestito colora la frase senza rompere la logica funzionale." },

{ q:"Quale principio collega gli accordi nel ciclo delle quinte discendenti?", opts:["Ogni accordo sale di una terza","Ogni accordo scende di una quinta (o sale di una quarta)","Ogni accordo è rivolto","Ogni accordo è in stato fondamentale"], a:1, fb:"Il ciclo delle quinte discendenti: ogni fondamentale è una quinta sotto la precedente. Questo movimento crea un'attrazione naturale — la dinamica più forte dell'armonia tonale." },
{ q:"Quale celebre standard jazz è basato sul ciclo delle quinte in minore?", opts:["All The Things You Are","Autumn Leaves","Misty","Round Midnight"], a:1, fb:"Autumn Leaves utilizza il ciclo delle quinte discendenti in G minore (e Bb maggiore) — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. È l'esempio pedagogico classico." },
{ q:"Il basso di ciaccona scende tipicamente:", opts:["Per quinte","Per gradi congiunti o per terze da I verso V","Per seconde aumentate","Per ottave"], a:1, fb:"Il basso di ciaccona crea una linea discendente congiunta o per terze — Do → Si♭ → La♭ → Sol in C minore. Questo basso è un ostinato su cui si sviluppano le variazioni." },
{ q:"Nel basso di ciaccona, si usa eccezionalmente la scala minore:", opts:["Armonica su tutti i gradi","Naturale sul V grado (Gm invece di G7)","Maggiore sul III grado","Dorica sul VI grado"], a:1, fb:"Nel basso di ciaccona, si usa la minore naturale sul V grado per fluidificare la linea discendente. L'eccezione Gm è specifica a questo contesto." },
{ q:"L'accordo napoletano è il grado:", opts:["♭III in primo rivolto","♭II in accordo maggiore, spesso in primo rivolto","IV abbassato","VII aumentato"], a:1, fb:"Il napoletano = ♭II maggiore. In C minore: Db maggiore. È generalmente presentato in 1° rivolto (♭II6) con la terza al basso." },
{ q:"La funzione armonica dell'accordo napoletano è:", opts:["Dominante","Tonica","Sottodominante","Neutra"], a:2, fb:"Il napoletano ha la funzione di sottodominante. In C minore, Db contiene Fa (IV grado) ma non Si. Prepara la dominante: ♭II6 → V7 → I." },
{ q:"In C minore, l'accordo napoletano è:", opts:["Ab maggiore","Db maggiore / F","Bb maggiore","Eb maggiore"], a:1, fb:"Il ♭II di C è Db (Reb maggiore). In primo rivolto: Db/F. È l'accordo napoletano di C minore." },
{ q:"Quale colore espressivo caratterizza l'accordo napoletano?", opts:["Gioioso e leggero","Drammatico e patetico","Misterioso e modale","Neutro e stabile"], a:1, fb:"Il semitono tra il ♭II e la tonica (Reb → Do) è carico di espressività drammatica. Il napoletano si ritrova in Beethoven, Chopin, e nella musica da film per evocare gravità o destino." },
{ q:"Lo schema classico di utilizzo del napoletano è:", opts:["♭II → I → V","♭II6 → V7 → I","I → ♭II → I","V → ♭II → V"], a:1, fb:"♭II6 → V7 → I: il napoletano prepara la dominante come una sottodominante rinforzata, poi la dominante risolve sulla tonica. Schema molto frequente nei romantici." },
{ q:"Nel ciclo delle quinte in C minore, quale accordo segue Fm7?", opts:["Cm","Bdim7","G7","EbMaj7"], a:1, fb:"Cm → Fm7 → Bdim7 → EbMaj7... Il Bdim7 è una quinta sotto Fm (Fa → Si). È il VII grado di C minore armonico." },

{ q:"La progressione Am–F–C–G in A minore prende F in prestito da:", opts:["A maggiore","C maggiore","La minore armonica","F maggiore"], a:0, fb:"In A minore, il VI grado naturale è Fa. F è il VI grado di A minore naturale — non è un prestito qui. F appartiene diatonicamente alla scala di A minore naturale." },
{ q:"La progressione C–Bb–F–C in C maggiore prende Bb in prestito da:", opts:["G maggiore","C minore","F maggiore","Bb maggiore"], a:2, fb:"Bb (Sib maggiore) non appartiene a C maggiore. È il VII grado di F maggiore, o il VII grado di C minore naturale. In C maggiore, è un prestito — spesso usato nel rock (I–bVII–IV–I)." },
{ q:"Quale progressione illustra meglio il prestito del IV minore in maggiore?", opts:["C–F–G7–C","C–Fm–G7–C","C–Dm–G7–C","C–Am–G7–C"], a:1, fb:"C–Fm–G7–C: il Fm è preso in prestito da C minore. È il prestito del IV grado minore in contesto maggiore — colore scuro sulla sottodominante, molto romantico." },
{ q:"In G maggiore, l'accordo napoletano sarebbe:", opts:["Ab maggiore","Ab maggiore / C","Eb maggiore","F maggiore"], a:1, fb:"Il ♭II di G è Ab (Lab). In primo rivolto con C (Do) al basso: Ab/C. È il napoletano di G maggiore." },
{ q:"Perché il ciclo delle quinte è così naturale all'orecchio?", opts:["Perché evita tutte le dissonanze","Perché il movimento di quinta è la consonanza più pura dopo l'ottava","Perché rimane nella stessa scala","Perché usa sempre accordi maggiori"], a:1, fb:"La quinta giusta (rapporto 3/2) è la consonanza più fondamentale dopo l'ottava. Una discesa di quinta crea un'attrazione acustica naturale — ecco perché questo movimento suona così inevitabile." },
{ q:"Un prestito è diverso da una modulazione perché:", opts:["Il prestito usa accordi rivolti","Il prestito è momentaneo — non si abbandona la tonalità principale","Il prestito è sempre seguito da una cadenza perfetta","Il prestito usa sempre il napoletano"], a:1, fb:"Un prestito è un colore passeggero — un accordo estraneo integrato senza spostare il centro tonale. La modulazione installa durevolmente una nuova tonalità con la propria cadenza." },
{ q:"La progressione C–Ab–Bb–C in C maggiore usa:", opts:["Due cadenze perfette","Due prestiti da C minore (Ab e Bb)","Una modulazione in Ab maggiore","Un basso di ciaccona"], a:1, fb:"Ab (Lab) e Bb (Sib) sono presi in prestito da C minore naturale. Questa progressione (I–bVI–bVII–I) è tipica del rock — due prestiti che creano un colore modale e massiccio." },

{ q:"Perché la scala minore naturale deriva dal VI grado della scala maggiore?", opts:["Per convenzione storica arbitraria","Perché partendo dal VI grado si ottiene la stessa sequenza T/½ traslata","Perché è la scala con meno alterazioni","Perché il VI grado è sempre minore"], a:1, fb:"La scala maggiore inizia sul I grado. Riprendendo la stessa sequenza di toni/semitoni a partire dal VI, si ottiene la scala minore relativa — stesse note, punto di partenza diverso." },
{ q:"In A minore naturale, quali note sono identiche a C maggiore?", opts:["6 note su 7","7 note su 7 — esattamente le stesse","5 note su 7","Nessuna nota in comune"], a:1, fb:"Am naturale e C maggiore condividono esattamente le stesse 7 note — A B C D E F G. Am è il relativo minore di C maggiore." },
{ q:"In C minore armonico, quale nota è alterata rispetto alla naturale?", opts:["Il IV grado (Fa)","Il VI grado (Lab)","Il VII grado (Si♭ → Si naturale)","Il II grado (Ré)"], a:2, fb:"La minore armonica alza il VII grado di un semitono: Si♭ (Bb) diventa Si naturale (B). Questo crea la sensibile e il tritono funzionale." },
{ q:"L'intervallo caratteristico della scala minore armonica è:", opts:["La terza aumentata tra I e III","Il tritono tra IV e VII","Il tono e mezzo tra VI e VII","La seconda diminuita tra V e VI"], a:2, fb:"Tra il VI (Lab) e il VII alzato (Si naturale) in C minore armonico, c'è 1 tono e mezzo (3 semitoni). Questo intervallo è la firma sonora della minore armonica — colore a volte definito orientale." },
{ q:"Qual è il V grado in C minore naturale?", opts:["Gm","G7","G maggiore","Gdim"], a:0, fb:"In C minore naturale, il VII grado è Bb (non alterato). L'accordo costruito su Sol è G–Bb–D = Gm. Senza la sensibile, non c'è tensione verso Cm." },
{ q:"Perché si usa la minore naturale sul I grado piuttosto che l'armonica?", opts:["Per tradizione","Perché la minore armonica creerebbe Cm con una 7a maggiore (ImMaj7) — accordo instabile","Perché la minore naturale è più bella","Perché il I grado non ha bisogno del tritono"], a:1, fb:"Sul I grado con minore armonica: C–Eb–G–B = CmMaj7. La 7a maggiore sulla tonica è molto instabile. Si preferisce la minore naturale per mantenere Cm o Cm7 come tonica stabile." },
{ q:"In D minore armonico, quale nota è alzata?", opts:["Sol (G)","Do (C)","Do# (C#)","Fa# (F#)"], a:2, fb:"D minore naturale: D E F G A Bb C. La minore armonica alza il VII grado C → C#. D minore armonico: D E F G A Bb C#." },
{ q:"In E minore armonico, la sensibile è:", opts:["Ré (D)","Ré# (D#)","Fa (F)","Sol (G)"], a:1, fb:"E minore naturale ha D come VII grado. La minore armonica lo alza: D → D#. La sensibile di E minore armonico è D#." },

{ q:"In G maggiore, quale accordo è preso in prestito nella progressione G–Eb–Bb–G?", opts:["Nessuno","Eb e Bb, presi in prestito da G minore","Solo Bb","Solo Eb"], a:1, fb:"In G maggiore, Eb (Mib) e Bb (Sib) non appartengono alla scala. Sono presi in prestito da G minore. La progressione G–bVI–bVII–G è tipica del rock." },
{ q:"In D maggiore, Bb è un prestito da:", opts:["D minore","G maggiore","A maggiore","F maggiore"], a:0, fb:"In D minore, il VI grado è Bb (Sib). Non è una nota di D maggiore — è un prestito da D minore in contesto di D maggiore." },
{ q:"Quale prestito è il più frequente nella musica classica e romantica?", opts:["Il bVII","Il bVI","Il IV minore (bIV)","Il bII"], a:2, fb:"Il prestito del IV grado minore (IV minore) è tra i più frequenti — F → Fm in C maggiore. Porta un colore scuro ed espressivo sulla sottodominante, molto apprezzato dal romanticismo." },
{ q:"Nella progressione A–F–C–G, F è:", opts:["Un prestito da A minore","Diatonico ad A maggiore","Un accordo di dominante secondaria","Un accordo napoletano"], a:1, fb:"A maggiore: A B C# D E F# G#. F naturale non appartiene ad A maggiore. F è invece il VI grado di A minore — è un prestito." },
{ q:"Il prestito I minore (es: Cm in C maggiore) ha la stessa funzione di:", opts:["Am","F","G7","Em"], a:0, fb:"Cm e Am hanno entrambi la funzione tonica (nessuno contiene F né B, il tritono di C). Cm può quindi sostituire Am come tonica alternativa, con un colore più scuro." },
{ q:"In C maggiore, qual è la funzione di Bb maggiore?", opts:["Dominante","Sottodominante","Tonica","Non ha una funzione chiara"], a:1, fb:"Bb (Sib maggiore) contiene Fa (F) ma non Si (B). Fa senza Si = funzione sottodominante. Bb può quindi sostituire F o Dm in una progressione SD–D–T." },
{ q:"La progressione C–Cm–C è un esempio di:", opts:["Modulazione","Pendolo","Minorizzazione momentanea (I → Im)","Cadenza plagale"], a:2, fb:"C → Cm → C: si minorizza momentaneamente la tonica — stessa fondamentale, ma la terza passa da E a Eb. Tecnica molto espressiva, usata nelle code e nei momenti drammatici." },
{ q:"In E maggiore, il prestito più frequente nel rock è:", opts:["Cm","Bm","D (bVII preso in prestito da E minore)","Ab"], a:2, fb:"D maggiore (Ré) è il bVII di E maggiore — preso in prestito da E minore. La progressione E–D–A–E è classica del rock (es.: numerosi brani di Led Zeppelin, Rolling Stones)." },
{ q:"La progressione I–bVII–IV–I in C maggiore è:", opts:["C–Bb–F–C","C–Bb–G–C","C–Ab–F–C","C–Bb–Dm–C"], a:0, fb:"C (I) – Bb (bVII, preso in prestito da C minore) – F (IV) – C (I). Bb è il prestito del VII grado minore. C–Bb–F–C è una progressione iconica del rock." },
{ q:"Quale accordo preso in prestito da C minore sostituisce Em (III grado) in C maggiore?", opts:["Cm","Eb","Ab","Fm"], a:1, fb:"Eb (Mib maggiore) è il III grado di C minore. Sostituisce Em con un colore più ampio e massiccio. La progressione C–Eb–F–G è comune nel rock e nel pop." },
{ q:"Perché si possono scambiare accordi tra tonalità omonime?", opts:["Perché hanno le stesse note","Perché condividono il tritono funzionale e quindi le stesse funzioni","Perché sono nella stessa armatura","Perché la melodia resta identica"], a:1, fb:"C maggiore e C minore condividono F e B (il tritono funzionale). Le funzioni sono determinate rispetto a questo tritono — gli accordi delle due tonalità possono quindi essere scambiati liberamente." },

{ q:"Il ciclo delle quinte completo in C maggiore è:", opts:["C–F–Bdim–Em–Am–Dm–G7–C","C–G–Dm–Am–Em–Bdim–F–C","C–Dm–Em–F–G–Am–Bdim–C","C–Am–F–Dm–Bdim–G7–Em–C"], a:0, fb:"C → F → Bdim → Em → Am → Dm → G7 → C. Ogni accordo è una quinta sotto il precedente nella scala di C maggiore." },
{ q:"In A minore, il ciclo delle quinte inizia con:", opts:["Am–Dm–G7–CMaj7–FMaj7–Bm7b5–E7–Am","Am–E7–Dm–G7–CMaj7–Am","Am–Dm–G7–Am","Am–G7–Dm–Am"], a:0, fb:"Am → Dm → G7 → CMaj7 → FMaj7 → Bm7b5 → E7 → Am. Stesso principio che in minore — ogni accordo scende di una quinta diatonica." },
{ q:"Perché il ciclo delle quinte discendenti è armonicamente così efficace?", opts:["Perché evita le dissonanze","Perché ogni fondamentale attrae la successiva per il movimento di quinta — la più forte attrazione di basso","Perché rimane in un'unica scala","Perché usa sempre accordi maggiori"], a:1, fb:"Il movimento di quinta discendente (o quarta ascendente) al basso crea l'attrazione più naturale dell'armonia tonale — è la stessa logica che fa risolvere V verso I." },
{ q:"In Autumn Leaves, il ciclo di quinte passa alternativamente da:", opts:["C maggiore a G maggiore","C minore a Eb maggiore","G minore a Bb maggiore — relativo minore e maggiore","A minore a C maggiore"], a:2, fb:"Autumn Leaves è in G minore / Bb maggiore (relativi). Il ciclo passa: Cm7–F7–BbMaj7–EbMaj7 (in Bb maggiore) poi Am7b5–D7–Gm (in G minore)." },
{ q:"Quale accordo completa la sequenza Cm–Fm7–Bdim7–… nel ciclo in C minore?", opts:["G7","AbMaj7","EbMaj7","Dm7b5"], a:2, fb:"Cm → Fm7 → Bdim7 → EbMaj7 → AbMaj7 → Dm7b5 → G7 → Cm. Dopo Bdim7, si scende di una quinta: Si → Mi♭ = EbMaj7." },
{ q:"Il ciclo delle quinte in modo maggiore omette spesso il III e il VII grado perché:", opts:["Sono troppo gravi","Sono meno usati e la loro funzione è ambigua","Non sono nella scala","Creano ottave parallele"], a:1, fb:"Em (III) e Bdim (VII) sono armonicamente più complessi e meno frequenti nelle progressioni comuni. In pratica, il ciclo maggiore abbreviato è spesso I–IV–V–I." },

{ q:"Il basso di ciaccona è usato principalmente come:", opts:["Una progressione di 8 accordi","Un ostinato che serve da base alle variazioni","Una serie di cadenze perfette","Un ciclo delle quinte in minore"], a:1, fb:"Il basso di ciaccona è un ostinato — una figura di basso ripetuta all'infinito su cui il compositore costruisce variazioni melodiche, ritmiche e armoniche." },
{ q:"Quale grande compositore barocco ha scritto una delle ciaccone più celebri per violino solo?", opts:["Vivaldi","Handel","Purcell","Bach"], a:3, fb:"La Ciaccona della Partita n°2 in Re minore di J.S. Bach è una delle opere più monumentali per violino solo — una serie di variazioni su un basso di ciaccona." },
{ q:"Il basso di ciaccona crea una tensione progressiva perché:", opts:["Sale verso l'acuto","Scende verso la dominante, creando un'attesa di risoluzione","Rimane sulla tonica","Usa accordi diminuiti"], a:1, fb:"Il basso scende per gradi (Do → Si♭ → La♭ → Sol in C minore) poi arriva su Sol (dominante), che chiama la risoluzione verso Cm. È una tensione costruita dal movimento melodico del basso." },
{ q:"Quale accordo del basso di ciaccona usa eccezionalmente la minore naturale?", opts:["Il I grado","Il IV grado","Il V grado (Gm invece di G7)","Il VI grado"], a:2, fb:"Nel basso di ciaccona, il V grado usa la minore naturale (Gm) per fluidificare la linea di basso discendente. Il G7 armonico sarebbe più teso ma meno naturale in questo contesto melodico." },
{ q:"La progressione Cm–Gm/Bb–Fm/Ab–G7 è un basso di ciaccona. Il basso suona:", opts:["Do–Sol–Fa–Sol","Do–Si♭–La♭–Sol","Do–Mi♭–Sol–Si","Do–Ré–Mi–Fa"], a:1, fb:"Il basso suona: Do (C) su Cm → Si♭ (Bb) su Gm/Bb → La♭ (Ab) su Fm/Ab → Sol (G) su G7. Linea discendente congiunta caratteristica." },
{ q:"Quale elemento musicale moderno deriva direttamente dalla tradizione della ciaccona?", opts:["Il chorus nel jazz","Il basso ostinato nel blues e nel funk","La modulazione per accordo pivot","L'accordo napoletano nel pop"], a:1, fb:"Il basso ostinato del blues (12-bar blues) e del funk sono discendenti diretti della ciaccona barocca — un basso ripetuto su cui si sviluppano le variazioni melodiche e ritmiche." },

{ q:"In G minore, l'accordo napoletano è:", opts:["Eb/G","Ab/C","Ab maggiore","Db maggiore"], a:1, fb:"Il ♭II di G è Ab (Lab maggiore). In primo rivolto con C al basso: Ab/C. È l'accordo napoletano di G minore." },
{ q:"In D minore, l'accordo napoletano è:", opts:["Eb maggiore","Eb/G","Bb maggiore","Gb maggiore"], a:1, fb:"Il ♭II di D è Eb (Mib maggiore). In primo rivolto con G al basso: Eb/G. L'accordo napoletano di D minore è Eb/G." },
{ q:"Il napoletano è generalmente presentato in primo rivolto perché:", opts:["È più facile da suonare","La terza al basso crea un movimento congiunto più fluido verso la dominante","Suona più forte","Per convenzione storica senza ragione acustica"], a:1, fb:"In primo rivolto (♭II6), il basso è la terza del ♭II. Questa voce scende di un semitono verso la sensibile della dominante — movimento congiunto molto espressivo e naturale." },
{ q:"Il semitono tra il ♭II e la tonica crea tensione perché:", opts:["È un intervallo raro","La vicinanza genera una forte attrazione — come la sensibile verso la tonica","Il ♭II è sempre instabile","Le due note distano 7 semitoni"], a:1, fb:"Reb → Do (Db → C) è un movimento di semitono discendente carico di espressività. Come la sensibile (B → C), questa vicinanza crea un'attrazione intensa — è l'essenza del pathos romantico." },
{ q:"Beethoven usa il napoletano in:", opts:["La Sonata al Chiaro di Luna (op.27)","La 9a Sinfonia","Entrambe"], a:0, fb:"La Sonata al Chiaro di Luna (op.27 n°2) usa l'accordo napoletano in modo caratteristico. Beethoven vi ricorre frequentemente per accentuare il carattere drammatico." },
{ q:"Il napoletano può apparire anche in modo maggiore?", opts:["No — è esclusivamente in modo minore","Sì — benché raro, si trova in Haydn e Schubert in maggiore","Sì, sempre","No — il ♭II esiste solo in minore"], a:1, fb:"Il napoletano è soprattutto caratteristico del modo minore, ma può apparire in maggiore — in Schubert, Beethoven (sonata op.31 n°2) e Haydn. In maggiore, l'effetto è ancora più sorprendente perché è ancora più estraneo alla tonalità." },
];

const questionsPt: Question[] = [{ q:"Por que a escala menor natural apresenta um problema harmônico?", opts:["Ela tem notas demais","Seu trítono não resolve para a tônica","Ela não tem o VII grau","Ela contém alterações demais"], a:1, fb:"No menor natural, o trítono está entre o II e o VI grau — ele não resolve para o I e III graus como no maior. Não há sensível funcional." },
{ q:"Como a escala menor harmônica resolve esse problema?", opts:["Eliminando o trítono","Elevando o VII grau meio tom","Abaixando o IV grau","Adicionando uma 8ª nota"], a:1, fb:"Elevar o VII grau cria uma sensível forte (B natural em vez de Bb em C menor) e restabelece um trítono funcional entre o IV e VII graus — como no maior." },
{ q:"O que a escala menor harmônica traz que a natural não tem?", opts:["Uma oitava adicional","Uma sensível e um trítono funcional","Três novas notas","Um acorde de dominante menor"], a:1, fb:"A menor harmônica recria a sensível (VII → I, meio tom ascendente) e o trítono funcional (IV + VII). Sem isso, o acorde de dominante seria menor (Gm em vez de G7)." },
{ q:"Em C menor harmônico, qual acorde forma a dominante?", opts:["Gm","G","G7","Dm"], a:2, fb:"Com o VII grau elevado (B natural), o acorde construído sobre Sol é G–B–D–F = G7. A sétima menor (F) vem da escala, e o B natural vem da menor harmônica." },
{ q:"Em quais graus se usa a menor natural em vez da harmônica?", opts:["IV e V","I e III","II e VII","V e VI"], a:1, fb:"O I grau (tônica) e o III grau (relativo maior) usam a menor natural para permanecerem estáveis. A menor harmônica nesses graus criaria intervalos instáveis demais (7ª maior, 5ª aumentada)." },
{ q:"Em C menor, qual é a diferença entre Gm (natural) e G7 (harmônico)?", opts:["A fundamental","A terça","A sétima e a terça — B♭ vs B natural","A quinta"], a:2, fb:"Em menor natural: G–Bb–D = Gm. Em menor harmônico: G–B–D–F = G7. A terça passa de Bb para B natural, criando a sensível e permitindo a resolução para Cm." },
{ q:"A fórmula da escala menor harmônica é:", opts:["T–T–½–T–T–T–½","T–½–T–T–½–T–T","T–½–T–T–½–1½–½","½–T–T–T–½–T–T"], a:2, fb:"T–½–T–T–½–1½–½: o tom e meio (1½) entre o VI e VII graus é característico da menor harmônica — um grande salto melódico que lhe confere sua cor oriental." },

{ q:"O que é um empréstimo harmônico?", opts:["Um acorde tocado duas vezes","Um acorde de uma tonalidade diferente, usado temporariamente","Uma inversão incomum","Uma modulação permanente"], a:1, fb:"Um empréstimo consiste em usar momentaneamente um acorde de outra tonalidade — sem abandonar a tonalidade principal. A função permanece identificável graças ao trítono funcional." },
{ q:"Por que C maior e C menor compartilham o mesmo trítono funcional?", opts:["Por acaso","Porque têm a mesma tônica e o trítono F–B é comum às duas escalas","Porque têm as mesmas notas","Porque a sensível é idêntica"], a:1, fb:"F e B (Fá e Si) estão presentes nas duas tonalidades — esse trítono determina as funções harmônicas. Por isso, os acordes das duas tonalidades podem ser trocados sem quebrar a lógica funcional." },
{ q:"Qual acorde de C menor pode substituir F (IV grau) em C maior?", opts:["Cm","Fm","Ab","Eb"], a:1, fb:"Fm é a subdominante de C menor. Assim como F, tem função subdominante (contém Fá mas não Si). Fm pode portanto substituir F em C maior — empréstimo muito expressivo." },
{ q:"A progressão C–Fm–C é um exemplo de:", opts:["Modulação em C menor","Empréstimo do IV grau menor","Cadência interrompida","Ciclo das quintas"], a:1, fb:"C (tônica) → Fm (subdominante emprestada de C menor) → C (tônica). O Fm é um empréstimo — permanece-se em C maior mas colore-se a frase com um toque menor." },
{ q:"Qual é a função de Ab (Lá♭ maior) em C maior?", opts:["Dominante","Subdominante","Tônica (emprestado de C menor)","Modulante"], a:2, fb:"Ab é o VI grau de C menor. Tem função tônica (não contém Fá nem Si). Em C maior, substitui Am como substituto tônico — empréstimo expressivo e luminoso." },
{ q:"O acorde Eb (Mi♭ maior) emprestado em C maior tem a função:", opts:["Dominante","Subdominante","Tônica","Nenhuma — está fora da tonalidade"], a:2, fb:"Eb é o III grau de C menor — função tônica. Em C maior, substitui Em. Muito usado no rock (I–bIII–IV–I) por sua cor ampla e massiva." },
{ q:"Para determinar a função de um acorde emprestado, usa-se:", opts:["Sua fundamental","O trítono funcional da tonalidade principal","Sua posição na escala menor","Seu número de notas"], a:1, fb:"O trítono funcional (F–B em C maior/menor) é a referência universal. Se contém F+B → dominante. F sozinho → subdominante. Nenhum dos dois → tônica." },
{ q:"A progressão C–Fm–C–G7–C usa Fm como:", opts:["Dominante","Substituto de Em","Subdominante emprestada","Acorde de passagem"], a:2, fb:"Fm tem função subdominante (contém Fá). Prepara G7 (dominante) depois C (tônica) = SD–D–T. O empréstimo colore a frase sem quebrar a lógica funcional." },

{ q:"Que princípio conecta os acordes no ciclo das quintas descendentes?", opts:["Cada acorde sobe uma terça","Cada acorde desce uma quinta (ou sobe uma quarta)","Cada acorde está invertido","Cada acorde está no estado fundamental"], a:1, fb:"O ciclo das quintas descendentes: cada fundamental está uma quinta abaixo da anterior. Esse movimento cria uma atração natural — a dinâmica mais forte da harmonia tonal." },
{ q:"Qual famoso standard de jazz é baseado no ciclo das quintas em menor?", opts:["All The Things You Are","Autumn Leaves","Misty","Round Midnight"], a:1, fb:"Autumn Leaves usa o ciclo das quintas descendentes em G menor (e Bb maior) — Cm7–F7–BbMaj7–EbMaj7–Am7b5–D7–Gm. É o exemplo pedagógico clássico." },
{ q:"O baixo da chacona desce tipicamente:", opts:["Por quintas","Por graus conjuntos ou por terças desde I até V","Por segundas aumentadas","Por oitavas"], a:1, fb:"O baixo da chacona cria uma linha descendente conjunta ou por terças — Do → Si♭ → Lá♭ → Sol em C menor. Esse baixo é um ostinato sobre o qual se desenvolvem variações." },
{ q:"No baixo da chacona, usa-se excepcionalmente a escala menor:", opts:["Harmônica em todos os graus","Natural no V grau (Gm em vez de G7)","Maior no III grau","Dórica no VI grau"], a:1, fb:"No baixo da chacona, usa-se a menor natural no V grau para tornar a linha descendente mais fluida. A exceção Gm é específica desse contexto." },
{ q:"O acorde napolitano é o grau:", opts:["♭III em primeira inversão","♭II em acorde maior, frequentemente em primeira inversão","IV abaixado","VII aumentado"], a:1, fb:"O napolitano = ♭II maior. Em C menor: Db maior. Geralmente apresentado em 1ª inversão (♭II6) com a terça no baixo." },
{ q:"A função harmônica do acorde napolitano é:", opts:["Dominante","Tônica","Subdominante","Neutra"], a:2, fb:"O napolitano tem função subdominante. Em C menor, Db contém Fá (IV grau) mas não Si. Prepara a dominante: ♭II6 → V7 → I." },
{ q:"Em C menor, o acorde napolitano é:", opts:["Ab maior","Db maior / F","Bb maior","Eb maior"], a:1, fb:"O ♭II de C é Db (Ré♭ maior). Em primeira inversão: Db/F. É o acorde napolitano de C menor." },
{ q:"Que cor expressiva caracteriza o acorde napolitano?", opts:["Alegre e leve","Dramática e patética","Misteriosa e modal","Neutra e estável"], a:1, fb:"O meio tom entre o ♭II e a tônica (Ré♭ → Do) é carregado de expressividade dramática. O napolitano aparece em Beethoven, Chopin e na música de cinema para evocar gravidade ou o destino." },
{ q:"O esquema clássico de uso do napolitano é:", opts:["♭II → I → V","♭II6 → V7 → I","I → ♭II → I","V → ♭II → V"], a:1, fb:"♭II6 → V7 → I: o napolitano prepara a dominante como uma subdominante reforçada, e então a dominante resolve na tônica. Esquema muito frequente nos compositores românticos." },
{ q:"No ciclo das quintas em C menor, qual acorde vem depois de Fm7?", opts:["Cm","Bdim7","G7","EbMaj7"], a:1, fb:"Cm → Fm7 → Bdim7 → EbMaj7... O Bdim7 é uma quinta abaixo de Fm (Fá → Si). É o VII grau de C menor harmônico." },

{ q:"A progressão Am–F–C–G em A menor empresta F de:", opts:["A maior","C maior","A menor harmônico","F maior"], a:0, fb:"Em A menor, o VI grau natural é Fá. F é o VI grau de A menor natural — não é um empréstimo aqui. F pertence diatonicamente à escala de A menor natural." },
{ q:"A progressão C–Bb–F–C em C maior empresta Bb de:", opts:["G maior","C menor","F maior","Bb maior"], a:2, fb:"Bb (Si♭ maior) não pertence a C maior. É o VII grau de F maior, ou o VII grau de C menor natural. Em C maior, é um empréstimo — frequentemente usado no rock (I–bVII–IV–I)." },
{ q:"Qual progressão ilustra melhor o empréstimo do IV menor em maior?", opts:["C–F–G7–C","C–Fm–G7–C","C–Dm–G7–C","C–Am–G7–C"], a:1, fb:"C–Fm–G7–C: o Fm é emprestado de C menor. É o empréstimo do IV grau menor em contexto maior — cor sombria na subdominante, muito romântica." },
{ q:"Em G maior, o acorde napolitano seria:", opts:["Ab maior","Ab maior / C","Eb maior","F maior"], a:1, fb:"O ♭II de G é Ab (Lá♭). Em primeira inversão com C (Do) no baixo: Ab/C. É o napolitano de G maior." },
{ q:"Por que o ciclo das quintas é tão natural ao ouvido?", opts:["Porque evita todas as dissonâncias","Porque o movimento de quinta é a consonância mais pura depois da oitava","Porque permanece na mesma escala","Porque usa sempre acordes maiores"], a:1, fb:"A quinta justa (relação 3/2) é a consonância mais fundamental depois da oitava. Uma descida de quinta cria uma atração acústica natural — por isso esse movimento soa tão inevitável." },
{ q:"Um empréstimo é diferente de uma modulação porque:", opts:["O empréstimo usa acordes invertidos","O empréstimo é momentâneo — não se abandona a tonalidade principal","O empréstimo é sempre seguido de uma cadência perfeita","O empréstimo usa sempre o napolitano"], a:1, fb:"Um empréstimo é uma cor passageira — um acorde estrangeiro integrado sem deslocar o centro tonal. A modulação instala duradouramente uma nova tonalidade com sua própria cadência." },
{ q:"A progressão C–Ab–Bb–C em C maior usa:", opts:["Duas cadências perfeitas","Dois empréstimos de C menor (Ab e Bb)","Uma modulação em Ab maior","Um baixo de chacona"], a:1, fb:"Ab (Lá♭) e Bb (Si♭) são emprestados de C menor natural. Essa progressão (I–bVI–bVII–I) é típica do rock — dois empréstimos que criam uma cor modal e massiva." },

{ q:"Por que a escala menor natural é derivada do VI grau da escala maior?", opts:["Por convenção histórica arbitrária","Porque partindo do VI grau se obtém a mesma sequência T/½ deslocada","Porque é a escala com menos alterações","Porque o VI grau é sempre menor"], a:1, fb:"A escala maior começa no I grau. Se retomamos a mesma sequência de tons/semitons a partir do VI, obtemos a escala menor relativa — mesmas notas, ponto de partida diferente." },
{ q:"Em A menor natural, quais notas são idênticas às de C maior?", opts:["6 notas de 7","7 notas de 7 — exatamente as mesmas","5 notas de 7","Nenhuma nota em comum"], a:1, fb:"Am natural e C maior compartilham exatamente as 7 mesmas notas — A B C D E F G. Am é o relativo menor de C maior." },
{ q:"Em C menor harmônico, qual nota é alterada em relação ao natural?", opts:["O IV grau (Fá)","O VI grau (Lá♭)","O VII grau (Si♭ → Si natural)","O II grau (Ré)"], a:2, fb:"A menor harmônica eleva o VII grau meio tom: Si♭ (Bb) torna-se Si natural (B). Isso cria a sensível e o trítono funcional." },
{ q:"O intervalo característico da escala menor harmônica é:", opts:["A terça aumentada entre I e III","O trítono entre IV e VII","O tom e meio entre VI e VII","A segunda diminuta entre V e VI"], a:2, fb:"Entre o VI grau (Lá♭) e o VII grau elevado (Si natural) em C menor harmônico, há 1 tom e meio (3 semitons). Esse intervalo é a assinatura sonora da menor harmônica — cor às vezes chamada de oriental." },
{ q:"Qual é o V grau em C menor natural?", opts:["Gm","G7","G maior","Gdim"], a:0, fb:"Em C menor natural, o VII grau é Bb (não alterado). O acorde construído sobre Sol é G–Bb–D = Gm. Sem a sensível, não há tensão em direção a Cm." },
{ q:"Por que se usa a menor natural no I grau em vez da harmônica?", opts:["Por tradição","Porque a menor harmônica criaria Cm com 7ª maior (ImMaj7) — acorde instável","Porque a menor natural é mais bonita","Porque o I grau não precisa de trítono"], a:1, fb:"No I grau com menor harmônica: C–Eb–G–B = CmMaj7. A 7ª maior sobre a tônica é muito instável. Prefere-se a menor natural para manter Cm ou Cm7 como tônica estável." },
{ q:"Em D menor harmônico, qual nota é elevada?", opts:["Sol (G)","Do (C)","Do# (C#)","Fá# (F#)"], a:2, fb:"D menor natural: D E F G A Bb C. A menor harmônica eleva o VII grau C → C#. D menor harmônico: D E F G A Bb C#." },
{ q:"Em E menor harmônico, a sensível é:", opts:["Ré (D)","Ré# (D#)","Fá (F)","Sol (G)"], a:1, fb:"E menor natural tem D como VII grau. A menor harmônica o eleva: D → D#. A sensível de E menor harmônico é D#." },

{ q:"Em G maior, qual acorde é emprestado na progressão G–Eb–Bb–G?", opts:["Nenhum","Eb e Bb, emprestados de G menor","Somente Bb","Somente Eb"], a:1, fb:"Em G maior, Eb (Mi♭) e Bb (Si♭) não pertencem à escala. São emprestados de G menor. A progressão G–bVI–bVII–G é típica do rock." },
{ q:"Em D maior, Bb é um empréstimo de:", opts:["D menor","G maior","A maior","F maior"], a:0, fb:"Em D menor, o VI grau é Bb (Si♭). Não é uma nota de D maior — é um empréstimo de D menor em contexto de D maior." },
{ q:"Qual empréstimo é o mais frequente na música clássica e romântica?", opts:["O bVII","O bVI","O IV menor (bIV)","O bII"], a:2, fb:"O empréstimo do IV grau menor (IV menor) é um dos mais frequentes — F → Fm em C maior. Traz uma cor sombria e expressiva sobre a subdominante, muito apreciada pelo romantismo." },
{ q:"Na progressão A–F–C–G, F é:", opts:["Um empréstimo de A menor","Diatônico a A maior","Um acorde de dominante secundária","Um acorde napolitano"], a:1, fb:"A maior: A B C# D E F# G#. F natural não pertence a A maior. Por outro lado, F é o VI grau de A menor — é um empréstimo." },
{ q:"O empréstimo do I menor (ex: Cm em C maior) tem a mesma função que:", opts:["Am","F","G7","Em"], a:0, fb:"Cm e Am têm ambos função tônica (nenhum contém F nem B, o trítono de C). Cm pode portanto substituir Am como tônica alternativa, com uma cor mais sombria." },
{ q:"Em C maior, qual é a função de Bb maior?", opts:["Dominante","Subdominante","Tônica","Não tem função clara"], a:1, fb:"Bb (Si♭ maior) contém Fá (F) mas não Si (B). Fá sozinho sem Si = função subdominante. Bb pode portanto substituir F ou Dm em uma progressão SD–D–T." },
{ q:"A progressão C–Cm–C é um exemplo de:", opts:["Modulação","Pêndulo","Minorização momentânea (I → Im)","Cadência plagal"], a:2, fb:"C → Cm → C: minoriza-se momentaneamente a tônica — mesma fundamental, mas a terça passa de E para Eb. Técnica muito expressiva, usada em codas e momentos dramáticos." },
{ q:"Em E maior, o empréstimo mais frequente no rock é:", opts:["Cm","Bm","D (bVII emprestado de E menor)","Ab"], a:2, fb:"D maior (Ré) é o bVII de E maior — emprestado de E menor. A progressão E–D–A–E é clássica do rock (ex.: muitas músicas de Led Zeppelin, Rolling Stones)." },
{ q:"A progressão I–bVII–IV–I em C maior é:", opts:["C–Bb–F–C","C–Bb–G–C","C–Ab–F–C","C–Bb–Dm–C"], a:0, fb:"C (I) – Bb (bVII, emprestado de C menor) – F (IV) – C (I). Bb é o empréstimo do VII grau menor. C–Bb–F–C é uma progressão icônica do rock." },
{ q:"Qual acorde emprestado de C menor substitui Em (III grau) em C maior?", opts:["Cm","Eb","Ab","Fm"], a:1, fb:"Eb (Mi♭ maior) é o III grau de C menor. Substitui Em com uma cor mais ampla e massiva. A progressão C–Eb–F–G é comum no rock e pop." },
{ q:"Por que se pode trocar acordes entre tonalidades homônimas?", opts:["Porque têm as mesmas notas","Porque compartilham o trítono funcional e portanto as mesmas funções","Porque estão na mesma armadura","Porque a melodia permanece idêntica"], a:1, fb:"C maior e C menor compartilham F e B (o trítono funcional). As funções são determinadas em relação a esse trítono — os acordes das duas tonalidades podem portanto ser trocados livremente." },

{ q:"O ciclo das quintas completo em C maior é:", opts:["C–F–Bdim–Em–Am–Dm–G7–C","C–G–Dm–Am–Em–Bdim–F–C","C–Dm–Em–F–G–Am–Bdim–C","C–Am–F–Dm–Bdim–G7–Em–C"], a:0, fb:"C → F → Bdim → Em → Am → Dm → G7 → C. Cada acorde é uma quinta abaixo do anterior na escala de C maior." },
{ q:"Em A menor, o ciclo das quintas começa por:", opts:["Am–Dm–G7–CMaj7–FMaj7–Bm7b5–E7–Am","Am–E7–Dm–G7–CMaj7–Am","Am–Dm–G7–Am","Am–G7–Dm–Am"], a:0, fb:"Am → Dm → G7 → CMaj7 → FMaj7 → Bm7b5 → E7 → Am. Mesmo princípio que em menor — cada acorde desce uma quinta diatônica." },
{ q:"Por que o ciclo das quintas descendentes é harmonicamente tão eficaz?", opts:["Porque evita as dissonâncias","Porque cada fundamental atrai a seguinte pelo movimento de quinta — a mais forte atração de baixo","Porque permanece em uma única escala","Porque usa sempre acordes maiores"], a:1, fb:"O movimento de quinta descendente (ou quarta ascendente) no baixo cria a atração mais natural da harmonia tonal — é a mesma lógica que faz V resolver para I." },
{ q:"Em Autumn Leaves, o ciclo de quintas passa alternadamente de:", opts:["C maior a G maior","C menor a Eb maior","G menor a Bb maior — relativo menor e maior","A menor a C maior"], a:2, fb:"Autumn Leaves está em G menor / Bb maior (relativos). O ciclo passa: Cm7–F7–BbMaj7–EbMaj7 (em Bb maior) depois Am7b5–D7–Gm (em G menor)." },
{ q:"Qual acorde completa a sequência Cm–Fm7–Bdim7–… no ciclo em C menor?", opts:["G7","AbMaj7","EbMaj7","Dm7b5"], a:2, fb:"Cm → Fm7 → Bdim7 → EbMaj7 → AbMaj7 → Dm7b5 → G7 → Cm. Depois de Bdim7, desce-se uma quinta: Si → Mi♭ = EbMaj7." },
{ q:"O ciclo das quintas em modo maior omite frequentemente o III e VII graus porque:", opts:["São muito graves","São menos usados e sua função é ambígua","Não estão na escala","Criam oitavas paralelas"], a:1, fb:"Em (III) e Bdim (VII) são harmonicamente mais complexos e menos frequentes nas progressões correntes. Na prática, o ciclo maior abreviado é frequentemente I–IV–V–I." },

{ q:"O baixo da chacona é usado principalmente como:", opts:["Uma progressão de 8 acordes","Um ostinato servindo de base às variações","Uma série de cadências perfeitas","Um ciclo das quintas em menor"], a:1, fb:"O baixo da chacona é um ostinato — uma figura de baixo repetida indefinidamente sobre a qual o compositor constrói variações melódicas, rítmicas e harmônicas." },
{ q:"Qual grande compositor barroco escreveu uma das chaconas mais célebres para violino solo?", opts:["Vivaldi","Handel","Purcell","Bach"], a:3, fb:"A Chacona da Partita nº2 em Ré menor de J.S. Bach é uma das obras mais monumentais para violino solo — uma série de variações sobre um baixo de chacona." },
{ q:"O baixo da chacona cria uma tensão progressiva porque:", opts:["Ele sobe em direção ao agudo","Ele desce em direção à dominante, criando uma expectativa de resolução","Ele permanece na tônica","Ele usa acordes diminutos"], a:1, fb:"O baixo desce por graus (Do → Si♭ → Lá♭ → Sol em C menor) e chega em Sol (dominante), que pede resolução para Cm. É uma tensão construída pelo movimento melódico do baixo." },
{ q:"Qual acorde do baixo da chacona usa excepcionalmente a menor natural?", opts:["O I grau","O IV grau","O V grau (Gm em vez de G7)","O VI grau"], a:2, fb:"No baixo da chacona, o V grau usa a menor natural (Gm) para tornar a linha de baixo descendente mais fluida. O G7 harmônico seria mais tenso, mas menos natural nesse contexto melódico." },
{ q:"A progressão Cm–Gm/Bb–Fm/Ab–G7 é um baixo de chacona. O baixo toca:", opts:["Do–Sol–Fá–Sol","Do–Si♭–Lá♭–Sol","Do–Mi♭–Sol–Si","Do–Ré–Mi–Fá"], a:1, fb:"O baixo toca: Do (C) em Cm → Si♭ (Bb) em Gm/Bb → Lá♭ (Ab) em Fm/Ab → Sol (G) em G7. Linha descendente conjunta característica." },
{ q:"Qual elemento musical moderno é diretamente derivado da tradição da chacona?", opts:["O chorus no jazz","O baixo ostinato no blues e no funk","A modulação por pivô","O acorde napolitano no pop"], a:1, fb:"O baixo ostinato do blues (12-bar blues) e do funk são descendentes diretos da chacona barroca — um baixo repetido sobre o qual se desenvolvem as variações melódicas e rítmicas." },

{ q:"Em G menor, o acorde napolitano é:", opts:["Eb/G","Ab/C","Ab maior","Db maior"], a:1, fb:"O ♭II de G é Ab (Lá♭ maior). Em primeira inversão com C no baixo: Ab/C. É o acorde napolitano de G menor." },
{ q:"Em D menor, o acorde napolitano é:", opts:["Eb maior","Eb/G","Bb maior","Gb maior"], a:1, fb:"O ♭II de D é Eb (Mi♭ maior). Em primeira inversão com G no baixo: Eb/G. O acorde napolitano de D menor é Eb/G." },
{ q:"O napolitano é geralmente apresentado em primeira inversão porque:", opts:["É mais fácil de tocar","A terça no baixo cria um movimento conjunto mais fluido em direção à dominante","Soa mais forte","Por convenção histórica sem razão acústica"], a:1, fb:"Em primeira inversão (♭II6), o baixo é a terça do ♭II. Essa voz desce meio tom em direção à sensível da dominante — movimento conjunto muito expressivo e natural." },
{ q:"O meio tom entre o ♭II e a tônica cria tensão porque:", opts:["É um intervalo raro","A proximidade gera uma forte atração — como a sensível em direção à tônica","O ♭II é sempre instável","As duas notas estão distantes 7 semitons"], a:1, fb:"Ré♭ → Do (Db → C) é um movimento de meio tom descendente carregado de expressividade. Como a sensível (B → C), essa proximidade cria uma atração intensa — é a essência do pathos romântico." },
{ q:"Beethoven usa o napolitano em:", opts:["A Sonata Ao Luar (op.27)","A 9ª Sinfonia","Nas duas"], a:0, fb:"A Sonata Ao Luar (op.27 nº2) usa o acorde napolitano de forma característica. Beethoven recorre a ele frequentemente para acentuar o caráter dramático." },
{ q:"O napolitano pode aparecer também em modo maior. Em C maior, seria:", opts:["Ab maior","Db maior / F","Gb maior","Bb maior"], a:1, fb:"Mesmo em C maior, o napolitano é Db/F. Seu uso é mais raro no maior porque cria um contraste mais brusco, mas permanece possível com um efeito muito dramático." },
{ q:"Após o napolitano, qual acorde chega quase sempre?", opts:["A tônica (I)","A subdominante (IV)","A dominante (V ou V7)","O VI grau"], a:2, fb:"O napolitano prepara a dominante: ♭II6 → V7. Depois a dominante resolve em I. O acorde napolitano é uma forma de pré-dominante — nunca resolve diretamente em I sem passar por V." },
{ q:"Qual nota do napolitano desce meio tom em direção à sensível da dominante?", opts:["A fundamental do ♭II","A terça do ♭II (que está no baixo em ♭II6)","A quinta do ♭II","Nenhuma — o napolitano sobe"], a:1, fb:"Em C menor, ♭II6 = Db/F. O baixo F (Fá) desce meio tom em direção a E (Mi) — a terça de G7. Este movimento de voz é uma das resoluções mais expressivas da harmonia tonal." },
];

